script:
// here root_element is provided by default
let recentList = root_element.querySelector('#recent-list');

let doctypes = [
    "Fiche Budgetaire",
    "Mandat Paiement",
    "Situation Paiement",
    "Personnel Administratif",
    "Annee Budgetaire",
    "Chapitre",
    "Article",
    "Faculte",
    "Budget Article",
    "Budget Chapitre",
    "Frais Mission",
    "Titre",
    "Facture Fournisseur",
    "Section",
    "Bon Commande",
    "Convention",
    "Depense Interne",
    "Fiche Transfert Credit",
    "Fournisseur",
    "Enseignant",
    "Etudiants"
];

let allResults = [];
let now = new Date();
let oneWeekAgo = new Date();
oneWeekAgo.setDate(now.getDate() - 7);

function chargerDT(dt, filtres) {
    return new Promise(function(resolve) {
        var args = {
            doctype: dt,
            fields: ["name", "modified"],
            order_by: "modified desc",
            limit_page_length: 20
        };
        if (filtres && filtres.length) args.filters = filtres;
        frappe.call({
            method: "frappe.client.get_list",
            args: args,
            callback: function(r) {
                if (r.message) {
                    r.message.forEach(function(row) {
                        if (new Date(row.modified) >= oneWeekAgo) {
                            row.doctype = dt;
                            allResults.push(row);
                        }
                    });
                }
                resolve();
            }
        });
    });
}

function afficher() {
    allResults.sort(function(a, b) { return new Date(b.modified) - new Date(a.modified); });
    recentList.innerHTML = "";
    if (!allResults.length) {
        recentList.innerHTML = "<li>Aucune opération récente</li>";
        return;
    }
    allResults.forEach(function(row) {
        var li = document.createElement("li");
        var date = new Date(row.modified).toLocaleString("fr-FR");
        li.textContent = "📄 " + row.doctype + " : " + row.name + " (" + date + ")";
        li.onclick = function() {
            frappe.set_route("Form", row.doctype, row.name);
        };
        recentList.appendChild(li);
    });
}

// ── Récupérer la faculté de l'utilisateur ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        if (!faculte) {
            // Pas de faculté → tout charger sans filtre
            Promise.all(doctypes.map(function(dt) {
                return chargerDT(dt, []);
            })).then(afficher);
            return;
        }

        // Étape 1 : Années budgétaires de la faculté
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: [['faculte', '=', faculte]],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // Étape 2 : Articles de la faculté
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name', 'chapitre'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles  = (rArt.message || []).map(function(a) { return a.name; });
                        var chapSet   = {};
                        (rArt.message || []).forEach(function(a) { if (a.chapitre) chapSet[a.chapitre] = true; });
                        var chapitres = Object.keys(chapSet);

                        var filtAn   = annees.length   ? [['annee_budgetaire', 'in', annees]]   : [];
                        var filtArt  = articles.length  ? [['article',          'in', articles]]  : [];
                        var filtChap = chapitres.length ? [['chapitre',         'in', chapitres]] : [];
                        var filtFac  = [['faculte', '=', faculte]];

                        // Fournisseurs via Facture Fournisseur
                        function chargerFournisseurs() {
                            return new Promise(function(resolve) {
                                if (!filtAn.length) {
                                    chargerDT('Fournisseur', []).then(resolve);
                                    return;
                                }
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Facture Fournisseur',
                                        fields: ['fournisseur'],
                                        filters: filtAn,
                                        limit_page_length: 0
                                    },
                                    callback: function(r) {
                                        var fournisseurs = [];
                                        (r.message || []).forEach(function(f) {
                                            if (f.fournisseur && !fournisseurs.includes(f.fournisseur))
                                                fournisseurs.push(f.fournisseur);
                                        });
                                        if (!fournisseurs.length) { resolve(); return; }
                                        chargerDT('Fournisseur', [['name', 'in', fournisseurs]]).then(resolve);
                                    }
                                });
                            });
                        }

                        var promesses = [
                            // Faculté directe
                            chargerDT('Annee Budgetaire',        filtFac),
                            chargerDT('Frais Mission',           filtFac),
                            chargerDT('Enseignant',              filtFac),
                            chargerDT('Etudiants',               filtFac),
                            chargerDT('Personnel Administratif', filtFac),
                            // Via annee_budgetaire
                            chargerDT('Fiche Budgetaire',        filtAn),
                            chargerDT('Depense Interne',         filtAn),
                            chargerDT('Mandat Paiement',         filtAn),
                            chargerDT('Fiche Transfert Credit',  filtAn),
                            chargerDT('Bon Commande',            filtAn),
                            chargerDT('Convention',              filtAn),
                            chargerDT('Facture Fournisseur',     filtAn),
                            chargerDT('Situation Paiement',      filtAn),
                            // Via article
                            chargerDT('Budget Article',          filtArt),
                            // Via chapitre
                            chargerDT('Budget Chapitre',         filtChap),
                            // Sans filtre
                            chargerDT('Chapitre',  []),
                            chargerDT('Article',   []),
                            chargerDT('Section',   []),
                            chargerDT('Titre',     []),
                            chargerDT('Faculte',   []),
                            // Fournisseur via Facture Fournisseur
                            chargerFournisseurs(),
                        ];

                        Promise.all(promesses).then(afficher);
                    }
                });
            }
        });
    }
});

