script:
let recentList = root_element.querySelector('#recent-list');

let doctypes = [
    "Fiche Budgetaire", "Mandat Paiement", "Situation Paiement",
    "Personnel Administratif", "Annee Budgetaire", "Chapitre",
    "Article", "Faculte", "Budget Article", "Budget Chapitre",
    "Frais Mission", "Titre", "Facture Fournisseur", "Section",
    "Bon Commande", "Convention", "Depense Interne",
    "Fiche Transfert Credit", "Fournisseur", "Enseignant", "Etudiants"
];

let allResults = [];
let now = new Date();
let oneWeekAgo = new Date();
oneWeekAgo.setDate(now.getDate() - 7);

function getIcon(dt) {
    var icons = {
        "Depense Interne":         "🧾",
        "Bon Commande":            "📋",
        "Convention":              "🤝",
        "Facture Fournisseur":     "📄",
        "Mandat Paiement":         "💸",
        "Fiche Transfert Credit":  "🔄",
        "Fiche Budgetaire":        "📑",
        "Budget Article":          "📊",
        "Budget Chapitre":         "📂",
        "Situation Paiement":      "💳",
        "Fournisseur":             "🏭",
        "Enseignant":              "👨‍🏫",
        "Etudiants":               "🎓",
        "Personnel Administratif": "👔",
        "Annee Budgetaire":        "📅",
        "Chapitre":                "🗂️",
        "Article":                 "📌",
        "Faculte":                 "🏫"
    };
    return icons[dt] || "📌";
}

function getBadge(action) {
    if (action === "creation")
        return '<span class="op-badge op-create">✚ Création</span>';
    return '<span class="op-badge op-update">✎ Modification</span>';
}

function ajouterResultats(dt, rows) {
    rows.forEach(function(row) {
        var modifiedDate = new Date(row.modified);
        if (modifiedDate >= oneWeekAgo) {
            var creationDate = new Date(row.creation);
            var diffSecondes = Math.abs(modifiedDate - creationDate) / 1000;
            allResults.push({
                name:     row.name,
                modified: row.modified,
                doctype:  dt,
                action:   diffSecondes < 2 ? "creation" : "modification"
            });
        }
    });
}

function chargerDT(dt, filtres) {
    return new Promise(function(resolve) {
        var args = {
            doctype: dt,
            fields: ["name", "modified", "creation"],
            order_by: "modified desc",
            limit_page_length: 50
        };
        if (filtres && filtres.length) args.filters = filtres;
        frappe.call({
            method: "frappe.client.get_list",
            args: args,
            callback: function(r) {
                if (r.message) ajouterResultats(dt, r.message);
                resolve();
            }
        });
    });
}

function chargerVersions() {
    return new Promise(function(resolve) {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Version",
                fields: ["name", "ref_doctype", "docname", "modified"],
                filters: [
                    ["ref_doctype", "in", doctypes],
                    ["modified", ">=", oneWeekAgo.toISOString().split("T")[0]]
                ],
                order_by: "modified desc",
                limit_page_length: 200
            },
            callback: function(r) {
                if (r.message) {
                    r.message.forEach(function(row) {
                        var existing = allResults.find(function(x) {
                            return x.name === row.docname && x.doctype === row.ref_doctype;
                        });
                        if (existing && existing.action !== "creation") {
                            existing.action = "modification";
                        }
                    });
                }
                resolve();
            }
        });
    });
}

function afficher(liste) {
    recentList.innerHTML = "";
    if (!liste.length) {
        recentList.innerHTML = "<li>Aucun résultat trouvé</li>";
        return;
    }
    liste.forEach(function(row) {
        var li = document.createElement("li");
        var date = new Date(row.modified).toLocaleString("fr-FR", {
            day: "2-digit", month: "2-digit", year: "numeric",
            hour: "2-digit", minute: "2-digit"
        });
        li.innerHTML =
            getBadge(row.action) +
            '<span class="op-name">' + getIcon(row.doctype) + ' ' + row.name + '</span>' +
            '<span class="op-doctype">' + row.doctype + '</span>' +
            '<span class="op-date">' + date + '</span>';
        li.onclick = function() {
            frappe.set_route("Form", row.doctype, row.name);
        };
        recentList.appendChild(li);
    });
}

function finaliser() {
    allResults.sort(function(a, b) {
        return new Date(b.modified) - new Date(a.modified);
    });

    if (!allResults.length) {
        recentList.innerHTML = "<li>Aucun historique (7 derniers jours)</li>";
        return;
    }

    afficher(allResults);

    var searchInput = root_element.querySelector('#recent-search');
    searchInput.addEventListener('input', function() {
        var q = this.value.toLowerCase().trim();
        if (!q) { afficher(allResults); return; }
        var filtered = allResults.filter(function(row) {
            return row.name.toLowerCase().includes(q) ||
                   row.doctype.toLowerCase().includes(q) ||
                   row.action.toLowerCase().includes(q);
        });
        afficher(filtered);
    });
}

// ══════════════════════════════════════════
//  LANCEMENT
// ══════════════════════════════════════════
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        if (!faculte) {
            Promise.all(doctypes.map(function(dt) {
                return chargerDT(dt, []);
            })).then(function() {
                chargerVersions().then(finaliser);
            });
            return;
        }

        // Étape 1 : Années budgétaires de la faculté
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: [['faculte', '=', faculte]],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // Étape 2 : Articles de la faculté
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name', 'chapitre'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles  = (rArt.message || []).map(function(a) { return a.name; });
                        var chapSet   = {};
                        (rArt.message || []).forEach(function(a) { if (a.chapitre) chapSet[a.chapitre] = true; });
                        var chapitres = Object.keys(chapSet);

                        var filtAn   = annees.length   ? [['annee_budgetaire', 'in', annees]]   : [];
                        var filtArt  = articles.length  ? [['article',          'in', articles]]  : [];
                        var filtChap = chapitres.length ? [['chapitre',         'in', chapitres]] : [];
                        var filtFac  = [['faculte', '=', faculte]];

                        // Fournisseur via Facture Fournisseur
                        function chargerFournisseurs() {
                            return new Promise(function(resolve) {
                                if (!filtAn.length) { resolve(); return; }
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Facture Fournisseur',
                                        fields: ['fournisseur'],
                                        filters: filtAn,
                                        limit_page_length: 0
                                    },
                                    callback: function(r) {
                                        var fournisseurs = [];
                                        (r.message || []).forEach(function(f) {
                                            if (f.fournisseur && !fournisseurs.includes(f.fournisseur))
                                                fournisseurs.push(f.fournisseur);
                                        });
                                        if (!fournisseurs.length) { resolve(); return; }
                                        chargerDT('Fournisseur', [['name', 'in', fournisseurs]]).then(resolve);
                                    }
                                });
                            });
                        }

                        var promesses = [
                            // Faculté directe
                            chargerDT('Annee Budgetaire',        filtFac),
                            chargerDT('Frais Mission',           filtFac),
                            chargerDT('Enseignant',              filtFac),
                            chargerDT('Etudiants',               filtFac),
                            chargerDT('Personnel Administratif', filtFac),
                            // Via annee_budgetaire
                            chargerDT('Fiche Budgetaire',        filtAn),
                            chargerDT('Depense Interne',         filtAn),
                            chargerDT('Mandat Paiement',         filtAn),
                            chargerDT('Fiche Transfert Credit',  filtAn),
                            chargerDT('Bon Commande',            filtAn),
                            chargerDT('Convention',              filtAn),
                            chargerDT('Facture Fournisseur',     filtAn),
                            chargerDT('Situation Paiement',      filtAn),
                            // Via article
                            chargerDT('Budget Article',          filtArt),
                            // Via chapitre
                            chargerDT('Budget Chapitre',         filtChap),
                            // Sans filtre
                            chargerDT('Chapitre',  []),
                            chargerDT('Article',   []),
                            chargerDT('Section',   []),
                            chargerDT('Titre',     []),
                            chargerDT('Faculte',   []),
                            // Fournisseur via Facture Fournisseur
                            chargerFournisseurs(),
                        ];

                        Promise.all(promesses).then(function() {
                            chargerVersions().then(finaliser);
                        });
                    }
                });
            }
        });
    }
});

style:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: 'Segoe UI', sans-serif; }

.recent-box {
    max-width: 100%;
    background: #fff;
    border-radius: 10px;
    box-shadow: 0 3px 12px rgba(0,0,0,0.1);
    overflow: hidden;
}

/* ── HEADER ── */
.recent-box h2 {
      
  background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%);
  border-radius: 12px; padding: 18px 24px; margin-bottom: 16px; color: #fff;
    color: #fff;
    text-align: center;
    padding: 25px 15px;
    font-size: 24px;
    font-weight: 700;
    margin: 0;
}

/* ── SEARCH ── */
#recent-search {
    display: block;
    width: calc(100% - 40px);
    margin: 15px 20px 10px;
    padding: 9px 12px;
    border: 2px solid #e9ecef;
    border-radius: 6px;
    font-size: 13px;
    background: #fff;
    outline: none;
    transition: border-color 0.2s;
    font-family: inherit;
}
#recent-search:focus { border-color: #667eea; }

/* ── LIST ── */
#recent-list {
    list-style: none;
    padding: 0 20px 20px;
    margin: 0;
    max-height: 340px;
    overflow-y: auto;
}

/* ── ITEM ── */
#recent-list li {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 12px 14px;
    font-size: 13px;
    color: #495057;
    border-bottom: 1px solid #f1f3f5;
    cursor: pointer;
    transition: background 0.15s;
}
#recent-list li:last-child { border-bottom: none; }
#recent-list li:hover { background: #f8f9fa; }

/* ── BADGE ACTION ── */
.op-badge {
    display: inline-block;
    padding: 3px 10px;
    border-radius: 99px;
    font-size: 11px;
    font-weight: 600;
    flex-shrink: 0;
}
.op-create { background: #dcfce7; color: #15803d; }
.op-update { background: #dbeafe; color: #1e40af; }

/* ── NAME ── */
.op-name {
    flex: 1;
    font-size: 13px;
    font-weight: 600;
    color: #333;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ── DOCTYPE ── */
.op-doctype {
    font-size: 11px;
    font-weight: 600;
    color: #6c757d;
    text-transform: uppercase;
    letter-spacing: 0.4px;
    white-space: nowrap;
    flex-shrink: 0;
}

/* ── DATE ── */
.op-date {
    font-size: 11.5px;
    color: #9ca3af;
    white-space: nowrap;
    flex-shrink: 0;
}

@media (max-width: 768px) {
    .op-doctype { display: none; }
}

script:
// here root_element is provided by default

var toutesLesFiches = [];
var fichesFiltrees  = [];
var filtreStatutActif = '';
var sfbArticlesFaculte = [];

function fmt(n) {
    if (!n) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function fmtDate(s) {
    if (!s) return '—';
    try {
        return new Intl.DateTimeFormat('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(s));
    } catch(e) { return s; }
}

function badgeType(t) {
    var map = { 'Économie':'type-economie', 'Provision':'type-provision', 'Dépense':'type-depense', 'Régularisation':'type-regularisation' };
    return '<span class="badge-type ' + (map[t]||'') + '">' + (t||'—') + '</span>';
}

function badgeStatut(s) {
    var map = {
        'Brouillon':         'badge-brouillon',
        'Signé Doyen':       'badge-signe',
        'Envoyé CF':         'badge-envoye',
        'Visé CF':           'badge-vise',
        'Rejeté':            'badge-rejete',
        'Rejeté Définitif':  'badge-rejete-def',
        'Archivé':           'badge-archive'
    };
    return '<span class="badge-statut ' + (map[s]||'badge-brouillon') + '">' + (s||'—') + '</span>';
}

function majCompteurs(liste) {
    var ids     = ['brouillon','signe','envoye','vise','rejete','rejete-def','archive'];
    var statuts = ['Brouillon','Signé Doyen','Envoyé CF','Visé CF','Rejeté','Rejeté Définitif','Archivé'];
    statuts.forEach(function(s, i) {
        var el = root_element.querySelector('#count-' + ids[i]);
        if (el) el.textContent = liste.filter(function(f) { return f.status === s; }).length;
    });
}

function afficherTableau(liste) {
    var tbody = root_element.querySelector('#table-body');
    if (!tbody) return;
    if (!liste.length) {
        tbody.innerHTML = '<tr><td colspan="7" class="no-data"><div class="no-data-icon">📭</div>Aucune fiche trouvée</td></tr>';
        return;
    }
    tbody.innerHTML = liste.map(function(f) {
        var chapLabel = (f.code_chapitre||'—') + (f.intitule_chapitre ? ' — '+f.intitule_chapitre : '');
        var artLabel  = (f.code_article ||'—') + (f.intitule_article  ? ' — '+f.intitule_article  : '');
        return '<tr onclick="window.location=\'/app/fiche-budgetaire/'+f.name+'\'" style="cursor:pointer">' +
            '<td>'+(f.numero_fiche||f.name)+'</td>' +
            '<td>'+badgeType(f.type_fiche)+'</td>' +
            '<td>'+chapLabel+'</td>' +
            '<td>'+artLabel+'</td>' +
            '<td>'+fmt(f.montant_operation)+'</td>' +
            '<td>'+fmtDate(f.date_signature_doyen)+'</td>' +
            '<td>'+badgeStatut(f.status)+'</td>' +
        '</tr>';
    }).join('');
}

function remplirSelectChapitres() {
    var sel = root_element.querySelector('#filtre-chapitre');
    if (!sel) return;
    sel.innerHTML = '<option value="">Tous les chapitres</option>';
    var vus = {};
    toutesLesFiches.forEach(function(f) {
        if (f.chapitre && !vus[f.chapitre]) {
            vus[f.chapitre] = true;
            var opt = document.createElement('option');
            opt.value = f.chapitre;
            opt.textContent = (f.code_chapitre||f.chapitre) + (f.intitule_chapitre ? ' — '+f.intitule_chapitre : '');
            sel.appendChild(opt);
        }
    });
}

function appliquerFiltres() {
    var type      = root_element.querySelector('#filtre-type').value;
    var chapitre  = root_element.querySelector('#filtre-chapitre').value;
    var dateDebut = root_element.querySelector('#filtre-date-debut').value;
    var dateFin   = root_element.querySelector('#filtre-date-fin').value;
    fichesFiltrees = toutesLesFiches.filter(function(f) {
        if (type              && f.type_fiche !== type)                   return false;
        if (chapitre          && f.chapitre   !== chapitre)               return false;
        if (filtreStatutActif && f.status     !== filtreStatutActif)      return false;
        if (dateDebut && (f.date_signature_doyen||'') < dateDebut)        return false;
        if (dateFin   && (f.date_signature_doyen||'') > dateFin)          return false;
        return true;
    });
    majCompteurs(fichesFiltrees);
    afficherTableau(fichesFiltrees);
}

function resetFiltres() {
    root_element.querySelector('#filtre-type').value       = '';
    root_element.querySelector('#filtre-chapitre').value   = '';
    root_element.querySelector('#filtre-date-debut').value = '';
    root_element.querySelector('#filtre-date-fin').value   = '';
    filtreStatutActif = '';
    root_element.querySelectorAll('.statut-card').forEach(function(c) { c.classList.remove('actif'); });
    fichesFiltrees = toutesLesFiches.slice();
    majCompteurs(fichesFiltrees);
    afficherTableau(fichesFiltrees);
}

root_element.querySelector('#btn-appliquer').addEventListener('click', appliquerFiltres);
root_element.querySelector('#btn-reset').addEventListener('click', resetFiltres);

root_element.querySelectorAll('.statut-card').forEach(function(card) {
    card.addEventListener('click', function() {
        var statut = this.dataset.statut;
        if (filtreStatutActif === statut) {
            filtreStatutActif = '';
            this.classList.remove('actif');
        } else {
            filtreStatutActif = statut;
            root_element.querySelectorAll('.statut-card').forEach(function(c) { c.classList.remove('actif'); });
            this.classList.add('actif');
        }
        appliquerFiltres();
    });
});

// ── Chargement avec filtre faculté ──
root_element.querySelector('#table-body').innerHTML =
    '<tr><td colspan="7" class="loading">⏳ Chargement...</td></tr>';

frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rA) {
                        sfbArticlesFaculte = (rA.message || []).map(function(a) { return a.name; });

                        var filters = sfbArticlesFaculte.length ? [['article', 'in', sfbArticlesFaculte]] : [];

                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Fiche Budgetaire',
                                fields: ['name', 'numero_fiche', 'type_fiche', 'chapitre', 'code_chapitre', 'intitule_chapitre', 'article', 'code_article', 'intitule_article', 'montant_operation', 'date_signature_doyen', 'status'],
                                filters: filters,
                                order_by: 'creation desc',
                                limit: 0
                            },
                            callback: function(r) {
                                toutesLesFiches = r.message || [];
                                fichesFiltrees  = toutesLesFiches.slice();
                                remplirSelectChapitres();
                                majCompteurs(fichesFiltrees);
                                afficherTableau(fichesFiltrees);
                            }
                        });
                    }
                });
            }
        });
    }
});

style:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: 'Segoe UI', sans-serif; }

.container-widget {
    max-width: 100%;
    background: #fff;
    border-radius: 10px;
    box-shadow: 0 3px 12px rgba(0,0,0,0.1);
    overflow: hidden;
}

.header {
    background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%);
    border-radius: 12px; padding: 18px 24px; margin-bottom: 16px; color: #fff;
    text-align: center; padding: 25px 15px;
}
.header h1 { font-size: 24px; color: #fff; margin-bottom: 5px; }
.header p  { font-size: 13px; opacity: 0.85; }

.filters-section {
    padding: 20px;
    background: #f8f9fa;
    border-bottom: 1px solid #e9ecef;
}
.filters-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px; margin-bottom: 15px;
}
.filter-group { display: flex; flex-direction: column; }
.filter-group label { font-weight: 600; margin-bottom: 6px; color: #495057; font-size: 13px; }
.filter-group select,
.filter-group input {
    padding: 9px 12px; border: 2px solid #e9ecef;
    border-radius: 6px; font-size: 13px; background: #fff;
    transition: border-color 0.2s; font-family: inherit;
}
.filter-group select:focus,
.filter-group input:focus { border-color: #1a2332; outline: none; }

.btn-apply {
    background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%);
    color: #fff; border: none; padding: 10px 25px; border-radius: 6px;
    font-weight: 600; cursor: pointer; transition: all 0.2s; font-family: inherit;
}
.btn-apply:hover { transform: translateY(-2px); box-shadow: 0 4px 10px rgba(26,35,50,0.4); }
.btn-reset {
    background: #fff; color: #1a2332; border: 2px solid #1a2332;
    padding: 10px 20px; border-radius: 6px; font-weight: 600;
    cursor: pointer; margin-left: 10px; transition: all 0.2s; font-family: inherit;
}
.btn-reset:hover { background: #1a2332; color: #fff; }

/* ── COMPTEURS ── */
.statut-cards {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 0; border-bottom: 1px solid #e9ecef;
}
.statut-card {
    padding: 16px 10px; text-align: center; cursor: pointer;
    border-right: 1px solid #e9ecef; transition: all 0.2s;
    position: relative;
}
.statut-card:last-child { border-right: none; }
.statut-card:hover { opacity: 0.85; }
.statut-card.actif::after {
    content: ''; position: absolute; bottom: 0; left: 0;
    width: 100%; height: 4px;
}

.statut-card.brouillon   { background: #f8f9fa; }
.statut-card.signe       { background: #f0fdf4; }
.statut-card.envoye      { background: #eff6ff; }
.statut-card.vise        { background: #f5f3ff; }
.statut-card.rejete      { background: #fff1f2; }
.statut-card.rejete-def  { background: #fef2f2; }
.statut-card.archive     { background: #fffbeb; }

.statut-card.brouillon.actif::after  { background: #6c757d; }
.statut-card.signe.actif::after      { background: #22c55e; }
.statut-card.envoye.actif::after     { background: #3b82f6; }
.statut-card.vise.actif::after       { background: #7c3aed; }
.statut-card.rejete.actif::after     { background: #ef4444; }
.statut-card.rejete-def.actif::after { background: #dc2626; }
.statut-card.archive.actif::after    { background: #f59e0b; }

.statut-count { font-size: 26px; font-weight: 700; line-height: 1; margin-bottom: 6px; }
.statut-card.brouillon  .statut-count { color: #6c757d; }
.statut-card.signe      .statut-count { color: #22c55e; }
.statut-card.envoye     .statut-count { color: #3b82f6; }
.statut-card.vise       .statut-count { color: #7c3aed; }
.statut-card.rejete     .statut-count { color: #ef4444; }
.statut-card.rejete-def .statut-count { color: #dc2626; }
.statut-card.archive    .statut-count { color: #f59e0b; }

.statut-label {
    font-size: 10px; font-weight: 600;
    text-transform: uppercase; letter-spacing: 0.5px; color: #6c757d;
}

/* ── TABLEAU ── */
.table-section { padding: 20px; }
.table-wrapper { overflow-x: auto; border-radius: 8px; border: 1px solid #e9ecef; }
table { width: 100%; border-collapse: collapse; }
thead { background: #f8f9fa; }
th {
    padding: 12px 15px; text-align: left; font-size: 12px;
    font-weight: 600; color: #6c757d; text-transform: uppercase;
    border-bottom: 2px solid #e9ecef;
}
td { padding: 13px 15px; font-size: 13px; color: #495057; border-bottom: 1px solid #f1f3f5; }
tbody tr:hover { background: #f8f9fa; cursor: pointer; }
tbody tr:last-child td { border-bottom: none; }

.badge-type {
    display: inline-block; padding: 3px 10px;
    border-radius: 99px; font-size: 11px; font-weight: 600;
}
.type-economie       { background: #e0f2fe; color: #0369a1; }
.type-provision      { background: #fce7f3; color: #9d174d; }
.type-depense        { background: #fef3c7; color: #92400e; }
.type-regularisation { background: #d1fae5; color: #065f46; }

.badge-statut {
    display: inline-block; padding: 3px 10px;
    border-radius: 99px; font-size: 11px; font-weight: 600;
}
.badge-brouillon  { background: #f1f5f9; color: #64748b; }
.badge-signe      { background: #dcfce7; color: #15803d; }
.badge-envoye     { background: #dbeafe; color: #1e40af; }
.badge-vise       { background: #ede9fe; color: #6d28d9; }
.badge-rejete     { background: #fee2e2; color: #dc2626; }
.badge-rejete-def { background: #fecaca; color: #991b1b; }
.badge-archive    { background: #fef9c3; color: #a16207; }

.loading, .no-data { text-align: center; padding: 35px; color: #6c757d; font-size: 13px; }
.no-data-icon { font-size: 36px; margin-bottom: 10px; }

@media (max-width: 768px) {
    .filters-grid { grid-template-columns: 1fr; }
    .statut-cards { grid-template-columns: repeat(3, 1fr); }
    .btn-reset { margin-left: 0; margin-top: 8px; display: block; }
}

script:
// ══════════════════════════════════════════
// JS
// ══════════════════════════════════════════
let allData        = [];
let chartChapitre  = null;
let chartCamembert = null;

let tableBody   = root_element.querySelector("#suivi-table tbody");
let searchInput = root_element.querySelector("#search");

function loadChartJs(callback) {
    if (window.Chart) { callback(); return; }
    let script = document.createElement("script");
    script.src = "https://cdn.jsdelivr.net/npm/chart.js";
    script.onload = callback;
    document.head.appendChild(script);
}

// ══════════════════════════════════════════
//  CHARGEMENT
// ══════════════════════════════════════════
function chargerDonnees(filtreArticles) {
    tableBody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:#aaa">⏳ Chargement...</td></tr>';

    var filtresBudget = [];
    if (filtreArticles && filtreArticles.length) {
        filtresBudget.push(['article', 'in', filtreArticles]);
    }

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Budget Article',
            fields: ['name', 'article'],
            filters: filtresBudget,
            limit_page_length: 0
        },
        callback: function(r) {
            if (!r.message || !r.message.length) {
                tableBody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:#aaa">Aucun budget article trouvé</td></tr>';
                return;
            }

            let budgets   = r.message;
            let total     = budgets.length;
            let compteur  = 0;
            let resultats = [];

            budgets.forEach(function(b) {

                // Étape 1 — Montant budget
                frappe.call({
                    method: 'frappe.client.get_value',
                    args: {
                        doctype:   'Budget Article',
                        filters:   { name: b.name },
                        fieldname: ['article', 'montant']
                    },
                    callback: function(res) {
                        let articleName   = res.message ? res.message.article  : b.article;
                        let budgetMontant = res.message ? (res.message.montant || 0) : 0;

                        // Étape 2 — Info article
                        frappe.call({
                            method: 'frappe.client.get_value',
                            args: {
                                doctype:   'Article',
                                filters:   { name: articleName },
                                fieldname: ['code_article', 'intitule_article', 'chapitre']
                            },
                            callback: function(art) {
                                let codeArticle     = art.message ? art.message.code_article     : articleName;
                                let intituleArticle = art.message ? art.message.intitule_article : '';
                                let chapitreCode    = art.message ? art.message.chapitre         : '—';

                                let appelsTermines = 0;
                                let totalDI = 0;
                                let totalFB = 0;

                                function fusionner() {
                                    appelsTermines++;
                                    if (appelsTermines === 2) {
                                        let totalDepense = totalDI + totalFB;
                                        let pct   = budgetMontant > 0 ? (totalDepense / budgetMontant * 100) : 0;
                                        let reste = budgetMontant - totalDepense;

                                        resultats.push({
                                            chapitre: chapitreCode,
                                            article:  codeArticle + (intituleArticle ? ' — ' + intituleArticle : ''),
                                            budget:   budgetMontant,
                                            depense:  totalDepense,
                                            di:       totalDI,
                                            fb:       totalFB,
                                            reste:    reste,
                                            pct:      pct
                                        });
                                        compteur++;
                                        if (compteur === total) afficher(resultats);
                                    }
                                }

                                // Étape 3a — Depense Interne Régularisé (A posteriori)
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Depense Interne',
                                        fields:  ['name'],
                                        filters: [
                                            ['article', '=', articleName],
                                            ['status',  '=', 'Régularisé']
                                        ],
                                        limit_page_length: 0
                                    },
                                    callback: function(deps) {
                                        let depenses = deps.message || [];
                                        if (!depenses.length) { fusionner(); return; }

                                        let cptDep = 0;
                                        depenses.forEach(function(dep) {
                                            frappe.call({
                                                method: 'frappe.client.get_value',
                                                args: {
                                                    doctype:   'Depense Interne',
                                                    filters:   { name: dep.name },
                                                    fieldname: ['montant_total']
                                                },
                                                callback: function(mv) {
                                                    totalDI += mv.message ? (mv.message.montant_total || 0) : 0;
                                                    cptDep++;
                                                    if (cptDep === depenses.length) fusionner();
                                                }
                                            });
                                        });
                                    }
                                });

                                // Étape 3b — Fiche Budgetaire Visé CF (A priori)
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Fiche Budgetaire',
                                        fields:  ['name'],
                                        filters: [
                                            ['article',    '=', articleName],
                                            ['status',     '=', 'Visé CF'],
                                            ['type_fiche', '=', 'Dépense']
                                        ],
                                        limit_page_length: 0
                                    },
                                    callback: function(fiches) {
                                        let liste = fiches.message || [];
                                        if (!liste.length) { fusionner(); return; }

                                        let cptFB = 0;
                                        liste.forEach(function(f) {
                                            frappe.call({
                                                method: 'frappe.client.get_value',
                                                args: {
                                                    doctype:   'Fiche Budgetaire',
                                                    filters:   { name: f.name },
                                                    fieldname: ['montant_operation']
                                                },
                                                callback: function(mv) {
                                                    totalFB += mv.message ? (mv.message.montant_operation || 0) : 0;
                                                    cptFB++;
                                                    if (cptFB === liste.length) fusionner();
                                                }
                                            });
                                        });
                                    }
                                });
                            }
                        });
                    }
                });
            });
        }
    });
}

// ══════════════════════════════════════════
//  AFFICHAGE
// ══════════════════════════════════════════
function afficher(data) {
    data.sort(function(a, b) {
        return (a.chapitre + a.article).localeCompare(b.chapitre + b.article);
    });
    allData = data;
    loadChartJs(function() {
        render(data);
        renderCharts(data);
    });
}

function render(data) {
    tableBody.innerHTML = '';
    if (!data.length) {
        tableBody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:#aaa">Aucune donnée</td></tr>';
        return;
    }
    data.forEach(function(row) {
        let fillClasse = row.pct >= 100 ? 'fill-danger' : row.pct >= 60 ? 'fill-warning' : 'fill-ok';
        let etat       = row.pct >= 100 ? '🔴 Dépassé'
                       : row.pct >= 90  ? '🟠 Critique'
                       : row.pct >= 60  ? '🟡 Alerte'
                       : '🟢 Normal';
        let largeur = Math.min(row.pct, 100).toFixed(1);

        tableBody.innerHTML +=
            '<tr>' +
            '<td>' + (row.chapitre || '—') + '</td>' +
            '<td>' + (row.article  || '—') + '</td>' +
            '<td>' + fmt(row.budget)  + '</td>' +
            '<td>' + fmt(row.depense) + '</td>' +
            '<td>' + fmt(row.reste)   + '</td>' +
            '<td>' +
                '<div>' + row.pct.toFixed(1) + '%</div>' +
                '<div class="progress-mini">' +
                    '<div class="progress-mini-fill ' + fillClasse + '" style="width:' + largeur + '%"></div>' +
                '</div>' +
            '</td>' +
            '<td>' + etat + '</td>' +
            '</tr>';
    });
}

function renderCharts(data) {
    let labels = [...new Set(data.map(function(d) { return d.chapitre || '—'; }))];

    let budgets = labels.map(function(c) {
        return data.filter(function(d) { return (d.chapitre || '—') === c; })
                   .reduce(function(s, r) { return s + (r.budget || 0); }, 0);
    });
    let depenses = labels.map(function(c) {
        return data.filter(function(d) { return (d.chapitre || '—') === c; })
                   .reduce(function(s, r) { return s + (r.depense || 0); }, 0);
    });

    if (chartChapitre) chartChapitre.destroy();
    chartChapitre = new Chart(root_element.querySelector("#chartParChapitre"), {
        type: 'bar',
        data: {
            labels: labels,
            datasets: [
                { label: 'Budget',  data: budgets,  backgroundColor: '#5b6af0' },
                { label: 'Dépensé', data: depenses, backgroundColor: '#f45b69' }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: { legend: { position: 'top' } },
            scales: { y: { beginAtZero: true } }
        }
    });

    let totalBudget = data.reduce(function(s, r) { return s + (r.budget  || 0); }, 0);
    let totalDep    = data.reduce(function(s, r) { return s + (r.depense || 0); }, 0);

    if (chartCamembert) chartCamembert.destroy();
    chartCamembert = new Chart(root_element.querySelector("#chartCamembert"), {
        type: 'doughnut',
        data: {
            labels: ['Reste', 'Dépensé'],
            datasets: [{
                data: [Math.max(totalBudget - totalDep, 0), totalDep],
                backgroundColor: ['#5b6af0', '#f45b69']
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: { legend: { position: 'top' } }
        }
    });
}

// ── Recherche ──
searchInput.addEventListener("input", function() {
    let q = this.value.toLowerCase();
    let filtered = allData.filter(function(r) {
        return (r.article  || '').toLowerCase().includes(q) ||
               (r.chapitre || '').toLowerCase().includes(q);
    });
    render(filtered);
    renderCharts(filtered);
});

function fmt(v) {
    return new Intl.NumberFormat('fr-DZ', {
        style: 'currency', currency: 'DZD',
        minimumFractionDigits: 0, maximumFractionDigits: 0
    }).format(v || 0);
}

// ══════════════════════════════════════════
//  LANCEMENT AVEC FILTRE FACULTÉ
// ══════════════════════════════════════════
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        if (!faculte) {
            chargerDonnees([]);
            return;
        }

        // Étape 1 : Années budgétaires de la faculté
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: [['faculte', '=', faculte]],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });
                if (!annees.length) { chargerDonnees([]); return; }

                // Étape 2 : Articles de la faculté
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: [['annee_budgetaire', 'in', annees]],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles = (rArt.message || []).map(function(a) { return a.name; });
                        chargerDonnees(articles);
                    }
                });
            }
        });
    }
});

