script:
// ══════════════════════════════════════════
// JS
// ══════════════════════════════════════════
let toutesLesDonnees = [];
let filtreActif      = { source: '', statut: '' };
let articlesApriori     = [];
let articlesAposteriori = [];
let articlesFaculte     = []; // articles filtrés par faculté

// ── Étape 0 : Faculté → Années → Articles ──
frappe.call({
    method: 'frappe.client.get_value',
    args: { doctype: 'User', filters: { name: frappe.session.user }, fieldname: 'faculte' },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name', 'code_article', 'intitule_article', 'type', 'chapitre'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0,
                        order_by: 'code_article asc'
                    },
                    callback: function(rArt) {
                        var arts = rArt.message || [];
                        articlesFaculte = arts.map(function(a) { return a.name; });

                        arts.forEach(function(a) {
                            if (a.type === 'A priori')     articlesApriori.push(a.name);
                            if (a.type === 'A posteriori') articlesAposteriori.push(a.name);
                        });

                        // Remplir select article
                        var sel = root_element.querySelector('#filtre-article');
                        arts.forEach(function(a) {
                            var o = document.createElement('option');
                            o.value = a.name;
                            o.setAttribute('data-type', a.type || '');
                            o.textContent = (a.code_article || a.name) + ' — ' + a.intitule_article + ' (' + (a.type || '?') + ')';
                            sel.appendChild(o);
                        });

                        // Remplir select chapitre (chapitres des articles de la faculté)
                        var chapitresSet = {};
                        arts.forEach(function(a) { if (a.chapitre) chapitresSet[a.chapitre] = true; });
                        var chapitreNames = Object.keys(chapitresSet);

                        if (chapitreNames.length) {
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Chapitre',
                                    fields: ['name', 'code', 'intitule'],
                                    filters: [['name', 'in', chapitreNames]],
                                    limit_page_length: 0,
                                    order_by: 'code asc'
                                },
                                callback: function(rC) {
                                    var selC = root_element.querySelector('#filtre-chapitre');
                                    (rC.message || []).forEach(function(c) {
                                        var o = document.createElement('option');
                                        o.value = c.name;
                                        o.textContent = (c.code || c.name) + ' - ' + c.intitule;
                                        selC.appendChild(o);
                                    });
                                }
                            });
                        }
                    }
                });
            }
        });
    }
});

// ── Filtre type ──
root_element.querySelector('#filtre-type').addEventListener('change', function() {
    let type = this.value;
    let sel  = root_element.querySelector('#filtre-article');
    sel.value = '';
    let opts = sel.querySelectorAll('option[data-type]');
    opts.forEach(function(o) {
        if (!type) o.style.display = '';
        else o.style.display = (o.getAttribute('data-type') === (type === 'apriori' ? 'A priori' : 'A posteriori')) ? '' : 'none';
    });

    let showDI = !type || type === 'aposteriori';
    let showFB = !type || type === 'apriori';
    root_element.querySelector('#bloc-di').style.display  = showDI ? '' : 'none';
    root_element.querySelector('#label-di').style.display = showDI ? '' : 'none';
    root_element.querySelector('#bloc-fb').style.display  = showFB ? '' : 'none';
    root_element.querySelector('#label-fb').style.display = showFB ? '' : 'none';
});

// ── Bouton Appliquer ──
root_element.querySelector('#btn-appliquer').addEventListener('click', function() {
    chargerDepenses();
});

// ── Bouton Réinitialiser ──
root_element.querySelector('#btn-reset').addEventListener('click', function() {
    root_element.querySelector('#filtre-type').value       = '';
    root_element.querySelector('#filtre-chapitre').value   = '';
    root_element.querySelector('#filtre-article').value    = '';
    root_element.querySelector('#filtre-date-debut').value = '';
    root_element.querySelector('#filtre-date-fin').value   = '';

    let opts = root_element.querySelectorAll('#filtre-article option[data-type]');
    opts.forEach(function(o) { o.style.display = ''; });

    root_element.querySelector('#bloc-di').style.display  = '';
    root_element.querySelector('#label-di').style.display = '';
    root_element.querySelector('#bloc-fb').style.display  = '';
    root_element.querySelector('#label-fb').style.display = '';

    filtreActif = { source: '', statut: '' };
    root_element.querySelectorAll('.statut-card').forEach(function(c) { c.classList.remove('actif'); });
    toutesLesDonnees = [];
    mettreAJourCompteurs([]);
    root_element.querySelector('#table-body').innerHTML =
        '<tr><td colspan="7" class="loading">Cliquez sur Appliquer pour charger les dépenses</td></tr>';
});

// ── Clic sur carte statut ──
root_element.querySelectorAll('.statut-card').forEach(function(card) {
    card.addEventListener('click', function() {
        let source = this.getAttribute('data-source');
        let statut = this.getAttribute('data-statut');

        if (filtreActif.source === source && filtreActif.statut === statut) {
            filtreActif = { source: '', statut: '' };
            this.classList.remove('actif');
        } else {
            filtreActif = { source: source, statut: statut };
            root_element.querySelectorAll('.statut-card').forEach(function(c) { c.classList.remove('actif'); });
            this.classList.add('actif');
        }
        afficherTableau(filtrerDonnees());
    });
});

// ══════════════════════════════════════════
//  CHARGEMENT — 2 sources filtrées par faculté
// ══════════════════════════════════════════
function chargerDepenses() {
    root_element.querySelector('#table-body').innerHTML =
        '<tr><td colspan="7" class="loading">⏳ Chargement...</td></tr>';

    let chapitre  = root_element.querySelector('#filtre-chapitre').value;
    let article   = root_element.querySelector('#filtre-article').value;
    let dateDebut = root_element.querySelector('#filtre-date-debut').value;
    let dateFin   = root_element.querySelector('#filtre-date-fin').value;
    let type      = root_element.querySelector('#filtre-type').value;

    let chargerDI = !type || type === 'aposteriori';
    let chargerFB = !type || type === 'apriori';

    if (article) {
        let opt = root_element.querySelector('#filtre-article option[value="' + article + '"]');
        if (opt) {
            let t = opt.getAttribute('data-type');
            chargerDI = (t === 'A posteriori');
            chargerFB = (t === 'A priori');
        }
    }

    let resultats   = [];
    let chargements = 0;
    if (!chargerDI) chargements++;
    if (!chargerFB) chargements++;

    function verifierFusion() {
        chargements++;
        if (chargements === 2) {
            toutesLesDonnees = resultats;
            mettreAJourCompteurs(toutesLesDonnees);
            afficherTableau(filtrerDonnees());
        }
    }

    // ── SOURCE 1 : Depense Interne ──
    if (chargerDI) {
        let filtresDI = [];
        if (chapitre)  filtresDI.push(['chapitre',    '=',  chapitre]);
        if (article)   filtresDI.push(['article',     '=',  article]);
        if (dateDebut) filtresDI.push(['date_depense', '>=', dateDebut]);
        if (dateFin)   filtresDI.push(['date_depense', '<=', dateFin]);

        // Filtre faculté
        var artsDI = article ? [article] : articlesAposteriori;
        if (artsDI.length) filtresDI.push(['article', 'in', artsDI]);

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Depense Interne',
                fields: ['name', 'numero_interne', 'date_depense', 'chapitre', 'intitule_chapitre', 'article', 'code_article', 'intitule_article', 'type_depense', 'status'],
                filters: filtresDI,
                limit_page_length: 0,
                order_by: 'date_depense desc'
            },
            callback: function(r) {
                (r.message || []).forEach(function(d) {
                    resultats.push({
                        source: 'DI', ref: d.numero_interne || d.name,
                        date: d.date_depense, chapitre: d.chapitre,
                        intitule_chapitre: d.intitule_chapitre,
                        article: d.code_article || d.article,
                        intitule_article: d.intitule_article,
                        type: d.type_depense, status: d.status
                    });
                });
                verifierFusion();
            }
        });
    }

    // ── SOURCE 2 : Fiche Budgetaire ──
    if (chargerFB) {
        let filtresFB = [['type_fiche', '=', 'Dépense']];
        if (chapitre)  filtresFB.push(['chapitre', '=',  chapitre]);
        if (article)   filtresFB.push(['article',  '=',  article]);
        if (dateDebut) filtresFB.push(['date_signature_doyen', '>=', dateDebut]);
        if (dateFin)   filtresFB.push(['date_signature_doyen', '<=', dateFin]);

        // Filtre faculté
        var artsFB = article ? [article] : articlesApriori;
        if (artsFB.length) filtresFB.push(['article', 'in', artsFB]);

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Fiche Budgetaire',
                fields: ['name', 'numero_fiche', 'date_signature_doyen', 'chapitre', 'intitule_chapitre', 'article', 'code_article', 'intitule_article', 'type_engagement_apriori', 'status'],
                filters: filtresFB,
                limit_page_length: 0,
                order_by: 'date_signature_doyen desc'
            },
            callback: function(r) {
                (r.message || []).forEach(function(d) {
                    resultats.push({
                        source: 'FB', ref: 'FB-' + (d.numero_fiche || d.name),
                        date: d.date_signature_doyen, chapitre: d.chapitre,
                        intitule_chapitre: d.intitule_chapitre,
                        article: d.code_article || d.article,
                        intitule_article: d.intitule_article,
                        type: d.type_engagement_apriori, status: d.status
                    });
                });
                verifierFusion();
            }
        });
    }
}

function filtrerDonnees() {
    if (!filtreActif.source && !filtreActif.statut) return toutesLesDonnees;
    return toutesLesDonnees.filter(function(d) {
        return d.source === filtreActif.source && d.status === filtreActif.statut;
    });
}

function mettreAJourCompteurs(donnees) {
    let di = donnees.filter(function(d) { return d.source === 'DI'; });
    let fb = donnees.filter(function(d) { return d.source === 'FB'; });

    let countDI = { 'Brouillon':0, 'Validé':0, 'Envoyé Comptable':0, 'Mandaté':0, 'Régularisé':0 };
    let countFB = { 'Brouillon':0, 'Signé Doyen':0, 'Envoyé CF':0, 'Visé CF':0, 'Archivé':0 };

    di.forEach(function(d) { if (countDI[d.status] !== undefined) countDI[d.status]++; });
    fb.forEach(function(d) { if (countFB[d.status] !== undefined) countFB[d.status]++; });

    root_element.querySelector('#count-di-brouillon').textContent  = countDI['Brouillon'];
    root_element.querySelector('#count-di-valide').textContent     = countDI['Validé'];
    root_element.querySelector('#count-di-envoye').textContent     = countDI['Envoyé Comptable'];
    root_element.querySelector('#count-di-mandate').textContent    = countDI['Mandaté'];
    root_element.querySelector('#count-di-regularise').textContent = countDI['Régularisé'];

    root_element.querySelector('#count-fb-brouillon').textContent  = countFB['Brouillon'];
    root_element.querySelector('#count-fb-signe').textContent      = countFB['Signé Doyen'];
    root_element.querySelector('#count-fb-envoye').textContent     = countFB['Envoyé CF'];
    root_element.querySelector('#count-fb-vise').textContent       = countFB['Visé CF'];
    root_element.querySelector('#count-fb-archive').textContent    = countFB['Archivé'];
}

function afficherTableau(donnees) {
    let tbody = root_element.querySelector('#table-body');
    if (!donnees.length) { afficherAucuneDonnee(); return; }

    donnees.sort(function(a, b) { return new Date(b.date) - new Date(a.date); });

    tbody.innerHTML = donnees.map(function(d) {
        return '<tr>' +
            '<td><strong>' + (d.ref || '—') + '</strong></td>' +
            '<td>' + formatDate(d.date) + '</td>' +
            '<td>' + (d.chapitre || '—') + (d.intitule_chapitre ? ' <small style="color:#aaa">— ' + d.intitule_chapitre + '</small>' : '') + '</td>' +
            '<td>' + (d.article || '—') + (d.intitule_article ? ' <small style="color:#aaa">— ' + d.intitule_article + '</small>' : '') + '</td>' +
            '<td>' + (d.type || '—') + '</td>' +
            '<td><span class="badge ' + (d.source === 'DI' ? 'badge-di' : 'badge-fb') + '">' + (d.source === 'DI' ? 'A posteriori' : 'A priori') + '</span></td>' +
            '<td>' + badgeStatut(d.status, d.source) + '</td>' +
        '</tr>';
    }).join('');
}

function afficherAucuneDonnee() {
    root_element.querySelector('#table-body').innerHTML =
        '<tr><td colspan="7" class="no-data"><div class="no-data-icon">📭</div><div>Aucune dépense trouvée</div></td></tr>';
}

function badgeStatut(s, source) {
    let mapDI = { 'Brouillon':'badge-brouillon','Validé':'badge-valide','Envoyé Comptable':'badge-envoye','Mandaté':'badge-mandate','Régularisé':'badge-regularise' };
    let mapFB = { 'Brouillon':'badge-brouillon','Signé Doyen':'badge-signe','Envoyé CF':'badge-envoye','Visé CF':'badge-vise','Archivé':'badge-archive' };
    let map = source === 'DI' ? mapDI : mapFB;
    return '<span class="badge ' + (map[s] || 'badge-brouillon') + '">' + (s || '—') + '</span>';
}

function formatDate(s) {
    if (!s) return '—';
    return new Intl.DateTimeFormat('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(s));
}

style:
/* ══════════════════════════════════════════
   CSS
══════════════════════════════════════════ */
* { margin: 0; padding: 0; box-sizing: border-box; font-family: 'Segoe UI', sans-serif; }

.container-widget {
    max-width: 100%;
    background: #fff;
    border-radius: 10px;
    box-shadow: 0 3px 12px rgba(0,0,0,0.1);
    overflow: hidden;
}

.header {
    background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%);
    color: #fff;
    text-align: center;
    padding: 25px 15px;
}
.header h1 { font-size: 24px; color: #fff; margin-bottom: 5px; }
.header p  { font-size: 13px; opacity: 0.85; }

.filters-section {
    padding: 20px;
    background: #f8f9fa;
    border-bottom: 1px solid #e9ecef;
}
.filters-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
    margin-bottom: 15px;
}
.filter-group { display: flex; flex-direction: column; }
.filter-group label { font-weight: 600; margin-bottom: 6px; color: #495057; font-size: 13px; }
.filter-group select,
.filter-group input {
    padding: 9px 12px;
    border: 2px solid #e9ecef;
    border-radius: 6px;
    font-size: 13px;
    background: #fff;
    transition: border-color 0.2s;
}
.filter-group select:focus,
.filter-group input:focus { border-color: #667eea; outline: none; }

.btn-apply {
    background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%);
    color: #fff; border: none;
    padding: 10px 25px; border-radius: 6px;
    font-weight: 600; cursor: pointer; transition: all 0.2s;
}
.btn-apply:hover { transform: translateY(-2px); box-shadow: 0 4px 10px rgba(26,35,50,0.4); }
.btn-reset {
    background: #fff; color: #1a2332;
    border: 2px solid #1a2332;
    padding: 10px 20px; border-radius: 6px;
    font-weight: 600; cursor: pointer; margin-left: 10px; transition: all 0.2s;
    font-family: inherit;
}
.btn-reset:hover { background: #1a2332; color: #fff; }

.statut-cards {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    border-bottom: 1px solid #e9ecef;
}
.statut-card {
    padding: 16px 10px;
    text-align: center;
    cursor: pointer;
    border-right: 1px solid #e9ecef;
    transition: all 0.2s;
    position: relative;
}
.statut-card:last-child { border-right: none; }
.statut-card:hover { opacity: 0.85; }
.statut-card.actif::after {
    content: '';
    position: absolute;
    bottom: 0; left: 0;
    width: 100%; height: 4px;
}

.statut-card.brouillon  { background: #f8f9fa; }
.statut-card.valide     { background: #f0fdf4; }
.statut-card.envoye     { background: #eff6ff; }
.statut-card.mandate    { background: #f5f3ff; }
.statut-card.regularise { background: #fffbeb; }
.statut-card.signe      { background: #fff7ed; }
.statut-card.vise       { background: #f0fdfa; }
.statut-card.archive    { background: #fdf4ff; }

.statut-card.brouillon.actif::after  { background: #6c757d; }
.statut-card.valide.actif::after     { background: #22c55e; }
.statut-card.envoye.actif::after     { background: #3b82f6; }
.statut-card.mandate.actif::after    { background: #7c3aed; }
.statut-card.regularise.actif::after { background: #f59e0b; }
.statut-card.signe.actif::after      { background: #f97316; }
.statut-card.vise.actif::after       { background: #14b8a6; }
.statut-card.archive.actif::after    { background: #a855f7; }

.statut-count { font-size: 28px; font-weight: 700; line-height: 1; margin-bottom: 4px; }
.statut-card.brouillon  .statut-count { color: #6c757d; }
.statut-card.valide     .statut-count { color: #22c55e; }
.statut-card.envoye     .statut-count { color: #3b82f6; }
.statut-card.mandate    .statut-count { color: #7c3aed; }
.statut-card.regularise .statut-count { color: #f59e0b; }
.statut-card.signe      .statut-count { color: #f97316; }
.statut-card.vise       .statut-count { color: #14b8a6; }
.statut-card.archive    .statut-count { color: #a855f7; }

.statut-label { font-size: 10px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px; color: #6c757d; }

.table-section { padding: 20px; }
.table-wrapper { overflow-x: auto; border-radius: 8px; border: 1px solid #e9ecef; }
table { width: 100%; border-collapse: collapse; }
thead { background: #f8f9fa; }
th { padding: 12px 15px; text-align: left; font-size: 12px; font-weight: 600; color: #6c757d; text-transform: uppercase; border-bottom: 2px solid #e9ecef; }
td { padding: 13px 15px; font-size: 13px; color: #495057; border-bottom: 1px solid #f1f3f5; }
tbody tr:hover { background: #f8f9fa; }
tbody tr:last-child td { border-bottom: none; }

.badge { display: inline-block; padding: 3px 10px; border-radius: 99px; font-size: 11px; font-weight: 600; }
.badge-brouillon  { background: #f1f5f9; color: #64748b; }
.badge-valide     { background: #dcfce7; color: #15803d; }
.badge-envoye     { background: #dbeafe; color: #1e40af; }
.badge-mandate    { background: #ede9fe; color: #6d28d9; }
.badge-regularise { background: #fef9c3; color: #a16207; }
.badge-signe      { background: #ffedd5; color: #c2410c; }
.badge-vise       { background: #ccfbf1; color: #0f766e; }
.badge-archive    { background: #fae8ff; color: #7e22ce; }
.badge-di         { background: #e0f2fe; color: #0369a1; }
.badge-fb         { background: #fce7f3; color: #9d174d; }

.loading, .no-data { text-align: center; padding: 35px; color: #6c757d; font-size: 13px; }
.no-data-icon { font-size: 36px; margin-bottom: 10px; }

@media (max-width: 768px) {
    .filters-grid { grid-template-columns: 1fr; }
    .statut-cards { grid-template-columns: repeat(3, 1fr); }
    .btn-reset { margin-left: 0; margin-top: 8px; display: block; }
}

script:
// here root_element is provided by default

var sfTous = [];

function sfFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function sfAfficher(liste) {
    var tbody = root_element.querySelector('#sf-tbody');
    if (!liste.length) {
        tbody.innerHTML = '<tr><td colspan="5" class="sf-empty">📭 Aucun fournisseur trouvé</td></tr>';
        return;
    }
    tbody.innerHTML = liste.map(function(f) {
        return '<tr onclick="window.location=\'/app/fournisseur/' + encodeURIComponent(f.fournisseur) + '\'" style="cursor:pointer">' +
            '<td class="sf-nom">'  + (f.fournisseur    || '—') + '</td>' +
            '<td>'                 + (f.raison_sociale  || '—') + '</td>' +
            '<td style="text-align:right;font-weight:700">' + f.nb + '</td>' +
            '<td class="sf-montant">' + sfFmt(f.total) + '</td>' +
            '<td style="text-align:center;color:#94a3b8;font-size:12px">' + (f.derniere || '—') + '</td>' +
        '</tr>';
    }).join('');
}

root_element.querySelector('#sf-search').addEventListener('input', function() {
    var q = this.value.toLowerCase();
    sfAfficher(sfTous.filter(function(f) {
        return (f.fournisseur    || '').toLowerCase().includes(q) ||
               (f.raison_sociale || '').toLowerCase().includes(q);
    }));
});

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Années budgétaires ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // ── Étape 2 : Articles ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles = (rArt.message || []).map(function(a) { return a.name; });

                        // ── Étape 3 : Depense Interne Fournisseur ──
                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Depense Interne',
                                fields: ['fournisseur', 'raison_sociale', 'date_depense', 'montant_total'],
                                filters: articles.length
                                    ? [['type_depense', '=', 'Fournisseur'], ['status', '=', 'Régularisé'], ['article', 'in', articles]]
                                    : [['type_depense', '=', 'Fournisseur'], ['status', '=', 'Régularisé']],
                                limit_page_length: 0
                            },
                            callback: function(rD) {
                                var deps = rD.message || [];

                                if (!deps.length) {
                                    root_element.querySelector('#sf-loading').textContent = 'Aucune dépense fournisseur trouvée';
                                    return;
                                }

                                var statsParFourn = {};
                                deps.forEach(function(d) {
                                    if (!d.fournisseur) return;
                                    var k = d.fournisseur;
                                    if (!statsParFourn[k]) statsParFourn[k] = { fournisseur: k, raison_sociale: d.raison_sociale || '—', nb: 0, total: 0, derniere: null };
                                    statsParFourn[k].nb++;
                                    statsParFourn[k].total += (d.montant_total || 0);
                                    if (!statsParFourn[k].derniere || d.date_depense > statsParFourn[k].derniere)
                                        statsParFourn[k].derniere = d.date_depense;
                                });

                                sfTous = Object.values(statsParFourn).sort(function(a, b) { return b.total - a.total; });

                                var totalDep  = sfTous.reduce(function(s, f) { return s + f.total; }, 0);
                                var totalFact = sfTous.reduce(function(s, f) { return s + f.nb;    }, 0);

                                root_element.querySelector('#sf-nb-fourn').textContent  = sfTous.length;
                                root_element.querySelector('#sf-total-dep').textContent = sfFmt(totalDep);
                                root_element.querySelector('#sf-nb-fact').textContent   = totalFact;
                                root_element.querySelector('#sf-sub').textContent       = sfTous.length + ' fournisseur(s) actifs';

                                root_element.querySelector('#sf-loading').style.display    = 'none';
                                root_element.querySelector('#sf-table-wrap').style.display = 'block';
                                sfAfficher(sfTous);
                            }
                        });
                    }
                });
            }
        });
    }
});

