script:
// here root_element is provided by default

function smFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function smBadge(status) {
    var map = {
        'En Attente': 'background:#fef3c7;color:#b45309',
        'Admis':      'background:#dcfce7;color:#15803d',
        'Rejeté':     'background:#fee2e2;color:#dc2626',
        'Payé':       'background:#dbeafe;color:#1d4ed8',
    };
    var s = map[status] || 'background:#f1f5f9;color:#64748b';
    return '<span style="font-size:10px;font-weight:700;padding:3px 9px;border-radius:20px;' + s + '">' + (status || '—') + '</span>';
}

function smSource(doc) {
    if (doc.type_source === 'Depense Interne' && doc.depense_interne)
        return '<a href="/app/depense-interne/' + doc.depense_interne + '" style="color:#3b82f6;font-size:11px">' + doc.depense_interne + '</a>';
    if (doc.type_source === 'Situation Paiement' && doc.situation_paiement)
        return '<a href="/app/situation-paiement/' + doc.situation_paiement + '" style="color:#3b82f6;font-size:11px">' + doc.situation_paiement + '</a>';
    if (doc.type_source === 'Fiche Depense' && doc.fiche_depense)
        return '<a href="/app/fiche-budgetaire/' + doc.fiche_depense + '" style="color:#3b82f6;font-size:11px">' + doc.fiche_depense + '</a>';
    return '—';
}

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Années budgétaires ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // ── Étape 2 : Articles ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles = (rArt.message || []).map(function(a) { return a.name; });

                        // ── Étape 3 : Mandats filtrés par article ──
                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Mandat Paiement',
                                fields: ['name', 'numero_mandat', 'date_mandat', 'montant_total',
                                         'status_admission', 'type_source', 'depense_interne',
                                         'situation_paiement', 'fiche_depense',
                                         'intitule_article', 'article', 'nom_raison_sociale',
                                         'objet_paiement', 'mode_paiement'],
                                filters: articles.length ? [['article', 'in', articles]] : [],
                                limit_page_length: 0,
                                order_by: 'date_mandat desc'
                            },
                            callback: function(r) {
                                var mandats = r.message || [];

                                root_element.querySelector('#sm-loading').style.display    = 'none';
                                root_element.querySelector('#sm-table-wrap').style.display = 'block';

                                var nbPaye    = mandats.filter(function(m) { return m.status_admission === 'Payé'; }).length;
                                var nbAdmis   = mandats.filter(function(m) { return m.status_admission === 'Admis'; }).length;
                                var nbAttente = mandats.filter(function(m) { return m.status_admission === 'En Attente'; }).length;
                                var nbRejete  = mandats.filter(function(m) { return m.status_admission === 'Rejeté'; }).length;

                                root_element.querySelector('#sm-nb-total').textContent = mandats.length;
                                root_element.querySelector('#sm-nb-paye').textContent  = nbPaye;
                                root_element.querySelector('#sm-nb-att').textContent   = nbAttente + nbAdmis;
                                root_element.querySelector('#sm-sub').textContent      = mandats.length + ' mandat(s) — ' + nbRejete + ' rejeté(s)';

                                if (!mandats.length) {
                                    root_element.querySelector('#sm-tbody').innerHTML =
                                        '<tr><td colspan="7" class="sm-empty">📭 Aucun mandat trouvé</td></tr>';
                                    return;
                                }

                                var html = '';
                                mandats.forEach(function(m) {
                                    html += '<tr onclick="window.location=\'/app/mandat-paiement/' + m.name + '\'" style="cursor:pointer">' +
                                        '<td style="font-family:monospace;font-weight:700;color:#1a2332">' + (m.numero_mandat || '—') + '</td>' +
                                        '<td style="font-size:11px;color:#64748b">' + (m.date_mandat || '—') + '</td>' +
                                        '<td style="font-size:11px">' + (m.nom_raison_sociale || '—') + '</td>' +
                                        '<td style="font-size:11px;color:#64748b">' + (m.intitule_article || m.article || '—') + '</td>' +
                                        '<td style="font-size:11px;color:#64748b">' + smSource(m) + '</td>' +
                                        '<td style="text-align:right;font-weight:600;font-family:monospace">' + smFmt(m.montant_total) + '</td>' +
                                        '<td style="text-align:center">' + smBadge(m.status_admission) + '</td>' +
                                    '</tr>';
                                });
                                root_element.querySelector('#sm-tbody').innerHTML = html;
                            }
                        });
                    }
                });
            }
        });
    }
});

