script:
// here root_element is provided by default

function teFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Années budgétaires ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // ── Étape 2 : Articles ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles = (rArt.message || []).map(function(a) { return a.name; });

                        var teBudgetTotal  = 0;
                        var teDepenseTotal = 0;

                        // ── Étape 3 : Budget Article ──
                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Budget Article',
                                fields: ['montant'],
                                filters: articles.length ? [['article', 'in', articles]] : [],
                                limit_page_length: 0
                            },
                            callback: function(rB) {
                                (rB.message || []).forEach(function(b) { teBudgetTotal += (b.montant || 0); });

                                // ── Étape 4 : Depense Interne Régularisé ──
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Depense Interne',
                                        fields: ['montant_total'],
                                        filters: articles.length
                                            ? [['status', '=', 'Régularisé'], ['article', 'in', articles]]
                                            : [['status', '=', 'Régularisé']],
                                        limit_page_length: 0
                                    },
                                    callback: function(rD) {
                                        (rD.message || []).forEach(function(d) { teDepenseTotal += (d.montant_total || 0); });

                                        // ── Étape 5 : Fiche Budgetaire Dépense Visé CF ──
                                        frappe.call({
                                            method: 'frappe.client.get_list',
                                            args: {
                                                doctype: 'Fiche Budgetaire',
                                                fields: ['montant_operation'],
                                                filters: articles.length
                                                    ? [['type_fiche', '=', 'Dépense'], ['status', '=', 'Visé CF'], ['article', 'in', articles]]
                                                    : [['type_fiche', '=', 'Dépense'], ['status', '=', 'Visé CF']],
                                                limit_page_length: 0
                                            },
                                            callback: function(rF) {
                                                (rF.message || []).forEach(function(f) { teDepenseTotal += (f.montant_operation || 0); });
                                                teAfficher(teBudgetTotal, teDepenseTotal);
                                            }
                                        });
                                    }
                                });
                            }
                        });
                    }
                });
            }
        });
    }
});

function teAfficher(teBudgetTotal, teDepenseTotal) {
    root_element.querySelector('#te-loading').style.display = 'none';
    root_element.querySelector('#te-body').style.display    = 'block';

    var pct   = teBudgetTotal > 0 ? Math.min((teDepenseTotal / teBudgetTotal) * 100, 100) : 0;
    var reste = teBudgetTotal - teDepenseTotal;

    root_element.querySelector('#te-budget-val').textContent = teFmt(teBudgetTotal);
    root_element.querySelector('#te-dep-val').textContent    = teFmt(teDepenseTotal);
    root_element.querySelector('#te-reste-val').textContent  = teFmt(reste);
    root_element.querySelector('#te-sub').textContent        = 'Taux global : ' + pct.toFixed(1) + '%';
    root_element.querySelector('#te-gauge-pct').textContent  = pct.toFixed(1) + '%';

    var statusEl = root_element.querySelector('#te-status');
    if (pct >= 90)      { statusEl.className = 'te-status te-status-danger'; statusEl.textContent = '🚨 Budget presque épuisé — intervention urgente requise'; }
    else if (pct >= 60) { statusEl.className = 'te-status te-status-warn';   statusEl.textContent = '⚠️ Budget significativement entamé — surveiller les dépenses'; }
    else                { statusEl.className = 'te-status te-status-ok';     statusEl.textContent = '✅ Taux d\'exécution normal — budget sous contrôle'; }

    var canvas = root_element.querySelector('#te-gauge');
    var ctx    = canvas.getContext('2d');
    var cx = 150, cy = 160, r = 120;
    var color = pct >= 90 ? '#ef4444' : pct >= 60 ? '#f59e0b' : '#10b981';

    ctx.beginPath();
    ctx.arc(cx, cy, r, Math.PI, 2 * Math.PI);
    ctx.lineWidth = 20;
    ctx.strokeStyle = '#e2e8f0';
    ctx.stroke();

    var endAngle = Math.PI + (pct / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(cx, cy, r, Math.PI, endAngle);
    ctx.lineWidth = 20;
    ctx.strokeStyle = color;
    ctx.lineCap = 'round';
    ctx.stroke();

    ctx.fillStyle = '#94a3b8';
    ctx.font = '12px Segoe UI';
    ctx.fillText('0%',   20, 170);
    ctx.fillText('100%', 255, 170);
}

