script:
// here root_element is provided by default

if (!window.Chart) {
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.0/chart.umd.min.js';
    s.onload = function() { bvcCharger(); };
    document.head.appendChild(s);
} else {
    bvcCharger();
}

function bvcFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function bvcCharger() {

    // ── Étape 0 : Faculté de l'utilisateur connecté ──
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'User',
            filters: { name: frappe.session.user },
            fieldname: 'faculte'
        },
        callback: function(r0) {
            var faculte = r0.message ? r0.message.faculte : null;

            // ── Étape 1 : Années budgétaires ──
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Annee Budgetaire',
                    fields: ['name'],
                    filters: faculte ? [['faculte', '=', faculte]] : [],
                    limit_page_length: 0
                },
                callback: function(rAn) {
                    var annees = (rAn.message || []).map(function(a) { return a.name; });

                    // ── Étape 2 : Articles de ces années ──
                    frappe.call({
                        method: 'frappe.client.get_list',
                        args: {
                            doctype: 'Article',
                            fields: ['name', 'chapitre'],
                            filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                            limit_page_length: 0
                        },
                        callback: function(rA) {
                            var articles = rA.message || [];
                            var articleNames = articles.map(function(a) { return a.name; });

                            if (!articleNames.length) {
                                root_element.querySelector('#bvc-loading').textContent = 'Aucun article trouvé pour cette faculté';
                                return;
                            }

                            // Construire map article → chapitre
                            var artToChapitre = {};
                            articles.forEach(function(a) { artToChapitre[a.name] = a.chapitre; });

                            // Récupérer les chapitres uniques de ces articles
                            var chapitresSet = {};
                            articles.forEach(function(a) { if (a.chapitre) chapitresSet[a.chapitre] = true; });
                            var chapitreNames = Object.keys(chapitresSet);

                            // ── Étape 3 : Détails des chapitres ──
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Chapitre',
                                    fields: ['name', 'code', 'intitule'],
                                    filters: [['name', 'in', chapitreNames]],
                                    limit_page_length: 0
                                },
                                callback: function(rC) {
                                    var chapitres = rC.message || [];

                                    // ── Étape 4 : Budget Article ──
                                    frappe.call({
                                        method: 'frappe.client.get_list',
                                        args: {
                                            doctype: 'Budget Article',
                                            fields: ['article', 'montant'],
                                            filters: [['article', 'in', articleNames]],
                                            limit_page_length: 0
                                        },
                                        callback: function(rB) {
                                            var budgets = rB.message || [];

                                            // Construire map chapitre → budget total
                                            var budgetParChapitre = {};
                                            chapitres.forEach(function(ch) { budgetParChapitre[ch.name] = 0; });
                                            budgets.forEach(function(b) {
                                                var ch = artToChapitre[b.article];
                                                if (ch && budgetParChapitre[ch] !== undefined) {
                                                    budgetParChapitre[ch] += (b.montant || 0);
                                                }
                                            });

                                            // ── Étape 5 : Depense Interne Régularisé ──
                                            frappe.call({
                                                method: 'frappe.client.get_list',
                                                args: {
                                                    doctype: 'Depense Interne',
                                                    fields: ['chapitre', 'montant_total'],
                                                    filters: [
                                                        ['status',   '=', 'Régularisé'],
                                                        ['chapitre', 'in', chapitreNames]
                                                    ],
                                                    limit_page_length: 0
                                                },
                                                callback: function(rD) {
                                                    var depAPParChapitre = {};
                                                    chapitres.forEach(function(ch) { depAPParChapitre[ch.name] = 0; });
                                                    (rD.message || []).forEach(function(d) {
                                                        if (depAPParChapitre[d.chapitre] !== undefined)
                                                            depAPParChapitre[d.chapitre] += (d.montant_total || 0);
                                                    });

                                                    // ── Étape 6 : Fiche Budgetaire Dépense Visé CF ──
                                                    frappe.call({
                                                        method: 'frappe.client.get_list',
                                                        args: {
                                                            doctype: 'Fiche Budgetaire',
                                                            fields: ['chapitre', 'montant_operation'],
                                                            filters: [
                                                                ['type_fiche', '=', 'Dépense'],
                                                                ['status',     '=', 'Visé CF'],
                                                                ['article',    'in', articleNames]
                                                            ],
                                                            limit_page_length: 0
                                                        },
                                                        callback: function(rF) {
                                                            var depPRParChapitre = {};
                                                            chapitres.forEach(function(ch) { depPRParChapitre[ch.name] = 0; });
                                                            (rF.message || []).forEach(function(f) {
                                                                if (depPRParChapitre[f.chapitre] !== undefined)
                                                                    depPRParChapitre[f.chapitre] += (f.montant_operation || 0);
                                                            });

                                                            // Construire résultats
                                                            var resultats = chapitres.map(function(ch) {
                                                                var budget  = budgetParChapitre[ch.name]  || 0;
                                                                var depense = (depAPParChapitre[ch.name] || 0) + (depPRParChapitre[ch.name] || 0);
                                                                return {
                                                                    code:     ch.code || ch.name,
                                                                    intitule: ch.intitule || ch.name,
                                                                    budget:   budget,
                                                                    depense:  depense,
                                                                    reste:    budget - depense
                                                                };
                                                            });

                                                            bvcAfficher(resultats);
                                                        }
                                                    });
                                                }
                                            });
                                        }
                                    });
                                }
                            });
                        }
                    });
                }
            });
        }
    });
}

function bvcAfficher(donnees) {
    root_element.querySelector('#bvc-loading').style.display = 'none';

    donnees = donnees.filter(function(d) { return d.budget > 0 || d.depense > 0; });

    var totalBudget  = donnees.reduce(function(s, d) { return s + d.budget;  }, 0);
    var totalDepense = donnees.reduce(function(s, d) { return s + d.depense; }, 0);
    var totalReste   = donnees.reduce(function(s, d) { return s + d.reste;   }, 0);

    root_element.querySelector('#bvc-total-budget').textContent = bvcFmt(totalBudget);
    root_element.querySelector('#bvc-total-dep').textContent    = bvcFmt(totalDepense);
    root_element.querySelector('#bvc-total-reste').textContent  = bvcFmt(totalReste);
    root_element.querySelector('#bvc-sub').textContent          = donnees.length + ' chapitre(s) avec données';

    if (!donnees.length) {
        root_element.querySelector('#bvc-loading').style.display = 'block';
        root_element.querySelector('#bvc-loading').textContent   = 'Aucune donnée à afficher';
        return;
    }

    var barWidth   = 90;
    var canvasW    = Math.max(donnees.length * barWidth, 600);
    var canvasWrap = root_element.querySelector('#bvc-canvas-wrap');
    var canvas     = root_element.querySelector('#bvc-chart');
    canvasWrap.style.width = canvasW + 'px';
    canvas.style.width     = canvasW + 'px';
    canvas.style.height    = '320px';
    canvas.width           = canvasW;
    canvas.height          = 320;

    root_element.querySelector('#bvc-chart-wrap').style.display = 'block';

    if (donnees.length > 10) {
        root_element.querySelector('#bvc-scroll-hint').style.display = 'block';
    }

    var labels = donnees.map(function(d) { return d.code; });

    var ctx = root_element.querySelector('#bvc-chart').getContext('2d');
    new Chart(ctx, {
        type: 'bar',
        data: {
            labels: labels,
            datasets: [
                {
                    label: 'Budget alloué',
                    data: donnees.map(function(d) { return d.budget; }),
                    backgroundColor: 'rgba(59,130,246,0.7)',
                    borderColor: '#3b82f6',
                    borderWidth: 1,
                    borderRadius: 4
                },
                {
                    label: 'Consommé',
                    data: donnees.map(function(d) { return d.depense; }),
                    backgroundColor: 'rgba(239,68,68,0.7)',
                    borderColor: '#ef4444',
                    borderWidth: 1,
                    borderRadius: 4
                },
                {
                    label: 'Restant',
                    data: donnees.map(function(d) { return Math.max(d.reste, 0); }),
                    backgroundColor: 'rgba(16,185,129,0.7)',
                    borderColor: '#10b981',
                    borderWidth: 1,
                    borderRadius: 4
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: {
                legend: { position: 'top', labels: { font: { size: 12 }, usePointStyle: true } },
                tooltip: {
                    callbacks: {
                        label: function(ctx) {
                            return ctx.dataset.label + ' : ' +
                                new Intl.NumberFormat('fr-DZ').format(Math.round(ctx.raw)) + ' DA';
                        }
                    }
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: {
                        callback: function(v) {
                            if (v >= 1000000) return (v/1000000).toFixed(1) + 'M';
                            if (v >= 1000)    return (v/1000).toFixed(0) + 'K';
                            return v;
                        }
                    },
                    grid: { color: '#f1f5f9' }
                },
                x: { grid: { display: false } }
            }
        }
    });
}

