script:
// here root_element is provided by default

var sbcTous     = [];
var sbcFiltres  = [];
var sbcStatutActif = '';

function sbcFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function sbcFmtDate(s) {
    if (!s) return '—';
    return new Intl.DateTimeFormat('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(s));
}

function sbcBadge(status) {
    var map = {
        'Brouillon':         'sbc-badge-brouillon',
        'Validé':            'sbc-badge-valide',
        'Envoyé CF':         'sbc-badge-envoye',
        'Visé CF':           'sbc-badge-vise',
        'Rejeté':            'sbc-badge-rejete',
        'Rejeté Définitif':  'sbc-badge-rejete-def',
        'Exécution':         'sbc-badge-execution',
        'Soldé':             'sbc-badge-solde'
    };
    return '<span class="sbc-badge ' + (map[status] || 'sbc-badge-brouillon') + '">' + (status || '—') + '</span>';
}

function sbcMajCompteurs(liste) {
    var counts = {
        'Brouillon': 0, 'Validé': 0, 'Envoyé CF': 0, 'Visé CF': 0,
        'Rejeté': 0, 'Rejeté Définitif': 0, 'Exécution': 0, 'Soldé': 0
    };
    liste.forEach(function(b) { if (counts[b.status] !== undefined) counts[b.status]++; });
    root_element.querySelector('#sbc-count-brouillon').textContent  = counts['Brouillon'];
    root_element.querySelector('#sbc-count-valide').textContent     = counts['Validé'];
    root_element.querySelector('#sbc-count-envoye').textContent     = counts['Envoyé CF'];
    root_element.querySelector('#sbc-count-vise').textContent       = counts['Visé CF'];
    root_element.querySelector('#sbc-count-rejete').textContent     = counts['Rejeté'];
    root_element.querySelector('#sbc-count-rejete-def').textContent = counts['Rejeté Définitif'];
    root_element.querySelector('#sbc-count-execution').textContent  = counts['Exécution'];
    root_element.querySelector('#sbc-count-solde').textContent      = counts['Soldé'];
}

function sbcMajKPIs(liste) {
    var totalMontant = liste.reduce(function(s, b) { return s + (b.total_ttc || 0); }, 0);
    var nbSolde      = liste.filter(function(b) { return b.status === 'Soldé'; }).length;
    root_element.querySelector('#sbc-nb-total').textContent      = liste.length;
    root_element.querySelector('#sbc-total-montant').textContent = sbcFmt(totalMontant);
    root_element.querySelector('#sbc-nb-solde').textContent      = nbSolde;
    root_element.querySelector('#sbc-sub').textContent           = liste.length + ' bon(s) de commande';
}

function sbcRemplirFournisseurs(liste) {
    var sel = root_element.querySelector('#sbc-filtre-fournisseur');
    var vus = {};
    liste.forEach(function(b) {
        if (b.prestataire && !vus[b.prestataire]) {
            vus[b.prestataire] = true;
            var opt = document.createElement('option');
            opt.value = b.prestataire;
            opt.textContent = b.raison_sociale || b.prestataire;
            sel.appendChild(opt);
        }
    });
}

function sbcAppliquerFiltres() {
    var statut      = root_element.querySelector('#sbc-filtre-statut').value;
    var fournisseur = root_element.querySelector('#sbc-filtre-fournisseur').value;
    var dateDebut   = root_element.querySelector('#sbc-filtre-debut').value;
    var dateFin     = root_element.querySelector('#sbc-filtre-fin').value;
    var search      = root_element.querySelector('#sbc-search').value.toLowerCase();

    sbcFiltres = sbcTous.filter(function(b) {
        if (statut         && b.status      !== statut)         return false;
        if (fournisseur    && b.prestataire !== fournisseur)     return false;
        if (sbcStatutActif && b.status      !== sbcStatutActif)  return false;
        if (dateDebut      && (b.date_commande || '') < dateDebut) return false;
        if (dateFin        && (b.date_commande || '') > dateFin)   return false;
        if (search) {
            var haystack = ((b.numero_bc || b.name) + ' ' + (b.prestataire || '') + ' ' + (b.raison_sociale || '') + ' ' + (b.objet_commande || '')).toLowerCase();
            if (!haystack.includes(search)) return false;
        }
        return true;
    });

    sbcMajCompteurs(sbcFiltres);
    sbcAfficher(sbcFiltres);
}

function sbcAfficher(liste) {
    var tbody = root_element.querySelector('#sbc-tbody');
    if (!liste.length) {
        tbody.innerHTML = '<tr><td colspan="7" class="sbc-empty">📭 Aucun bon de commande trouvé</td></tr>';
        return;
    }
    tbody.innerHTML = liste.map(function(b) {
        return '<tr onclick="window.location=\'/app/bon-commande/' + b.name + '\'" style="cursor:pointer">' +
            '<td style="font-family:monospace;font-weight:700;color:#1a2332">' + (b.numero_bc || b.name) + '</td>' +
            '<td style="color:#64748b;font-size:11px">' + sbcFmtDate(b.date_commande) + '</td>' +
            '<td>' + (b.raison_sociale || b.prestataire || '—') + '</td>' +
            '<td style="font-size:11px;color:#64748b;max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + (b.objet_commande || '—') + '</td>' +
            '<td style="font-size:11px;color:#64748b">' + (b.code_article || b.article || '—') + '</td>' +
            '<td style="text-align:right;font-weight:600;font-family:monospace">' + sbcFmt(b.total_ttc) + '</td>' +
            '<td style="text-align:center">' + sbcBadge(b.status) + '</td>' +
        '</tr>';
    }).join('');
}

// ── Cartes statut cliquables ──
root_element.querySelectorAll('.sbc-statut-card').forEach(function(card) {
    card.addEventListener('click', function() {
        var statut = this.getAttribute('data-statut');
        if (sbcStatutActif === statut) {
            sbcStatutActif = '';
            this.classList.remove('actif');
        } else {
            sbcStatutActif = statut;
            root_element.querySelectorAll('.sbc-statut-card').forEach(function(c) { c.classList.remove('actif'); });
            this.classList.add('actif');
        }
        sbcAppliquerFiltres();
    });
});

// ── Filtres live ──
['#sbc-filtre-statut', '#sbc-filtre-fournisseur', '#sbc-filtre-debut', '#sbc-filtre-fin'].forEach(function(sel) {
    root_element.querySelector(sel).addEventListener('change', sbcAppliquerFiltres);
});
root_element.querySelector('#sbc-search').addEventListener('input', sbcAppliquerFiltres);

// ── Reset ──
root_element.querySelector('#sbc-btn-reset').addEventListener('click', function() {
    root_element.querySelector('#sbc-filtre-statut').value      = '';
    root_element.querySelector('#sbc-filtre-fournisseur').value = '';
    root_element.querySelector('#sbc-filtre-debut').value       = '';
    root_element.querySelector('#sbc-filtre-fin').value         = '';
    root_element.querySelector('#sbc-search').value             = '';
    sbcStatutActif = '';
    root_element.querySelectorAll('.sbc-statut-card').forEach(function(c) { c.classList.remove('actif'); });
    sbcFiltres = sbcTous.slice();
    sbcMajCompteurs(sbcFiltres);
    sbcAfficher(sbcFiltres);
});

// ══════════════════════════════════════════════════
//  CHARGEMENT avec filtre faculté
// ══════════════════════════════════════════════════
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rA) {
                        var articles = (rA.message || []).map(function(a) { return a.name; });

                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Bon Commande',
                                fields: ['name', 'date_commande', 'prestataire', 'article', 'status', 'annee_budgetaire'],
                                filters: articles.length ? [['article', 'in', articles]] : [],
                                limit_page_length: 0,
                                order_by: 'date_commande desc'
                            },
                            callback: function(r) {
                                var bcs = r.message || [];

                                if (!bcs.length) {
                                    root_element.querySelector('#sbc-loading').style.display    = 'none';
                                    root_element.querySelector('#sbc-table-wrap').style.display = 'block';
                                    sbcTous = []; sbcFiltres = [];
                                    sbcMajKPIs([]); sbcMajCompteurs([]); sbcAfficher([]);
                                    return;
                                }

                                var total    = bcs.length;
                                var compteur = 0;

                                bcs.forEach(function(b) {
                                    frappe.call({
                                        method: 'frappe.client.get_value',
                                        args: {
                                            doctype:   'Bon Commande',
                                            filters:   { name: b.name },
                                            fieldname: ['numero_bon_commande', 'raison_sociale', 'objet_detaille', 'code_article', 'total_ttc']
                                        },
                                        callback: function(rv) {
                                            b.numero_bc      = rv.message ? (rv.message.numero_bon_commande || b.name) : b.name;
                                            b.raison_sociale = rv.message ? (rv.message.raison_sociale      || '')     : '';
                                            b.objet_commande = rv.message ? (rv.message.objet_detaille      || '')     : '';
                                            b.code_article   = rv.message ? (rv.message.code_article        || '')     : '';
                                            b.total_ttc      = rv.message ? (rv.message.total_ttc           || 0)      : 0;
                                            compteur++;
                                            if (compteur === total) {
                                                root_element.querySelector('#sbc-loading').style.display    = 'none';
                                                root_element.querySelector('#sbc-table-wrap').style.display = 'block';
                                                sbcTous    = bcs;
                                                sbcFiltres = bcs.slice();
                                                sbcMajKPIs(sbcTous);
                                                sbcMajCompteurs(sbcTous);
                                                sbcRemplirFournisseurs(sbcTous);
                                                sbcAfficher(sbcFiltres);
                                            }
                                        }
                                    });
                                });
                            }
                        });
                    }
                });
            }
        });
    }
});

style:
.sbc-wrap { font-family: 'Segoe UI', sans-serif; color: #1a2332; }

.sbc-header {
    display: flex; align-items: center; justify-content: space-between;
    background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%);
    border-radius: 12px; padding: 18px 24px; margin-bottom: 16px; color: #fff;
}
.sbc-header-left { display: flex; align-items: center; gap: 14px; }
.sbc-icon  { font-size: 28px; }
.sbc-title { font-size: 16px; font-weight: 700; }
.sbc-sub   { font-size: 12px; opacity: .7; margin-top: 2px; }
.sbc-header-right { display: flex; gap: 12px; }
.sbc-kpi { border-radius: 10px; padding: 10px 16px; text-align: center; min-width: 110px; background: rgba(255,255,255,.12); }
.sbc-kpi-montant { background: rgba(59,130,246,.3); }
.sbc-kpi-solde   { background: rgba(16,185,129,.3); }
.sbc-kpi-val { font-size: 13px; font-weight: 700; color: #fff; }
.sbc-kpi-lbl { font-size: 10px; color: rgba(255,255,255,.8); margin-top: 2px; }

/* Cartes statut */
.sbc-statuts {
    display: flex; gap: 10px; margin-bottom: 16px; flex-wrap: wrap;
}
.sbc-statut-card {
    flex: 1; min-width: 100px;
    background: #fff; border: 2px solid #e2e8f0;
    border-radius: 10px; padding: 12px; text-align: center;
    cursor: pointer; transition: all .2s;
}
.sbc-statut-card:hover { border-color: #1a2332; transform: translateY(-2px); }
.sbc-statut-card.actif { border-color: #1a2332; background: #1a2332; color: #fff; }
.sbc-statut-card.actif .sbc-statut-lbl { color: rgba(255,255,255,.8); }
.sbc-statut-count { font-size: 22px; font-weight: 800; color: #1a2332; }
.sbc-statut-card.actif .sbc-statut-count { color: #fff; }
.sbc-statut-lbl { font-size: 11px; color: #64748b; margin-top: 4px; }

/* Filtres */
.sbc-filtres {
    display: flex; gap: 10px; flex-wrap: wrap;
    background: #f8fafc; border-radius: 10px;
    padding: 12px; margin-bottom: 16px;
}
.sbc-select, .sbc-input {
    padding: 7px 12px; border: 1px solid #e2e8f0;
    border-radius: 7px; font-size: 12px; color: #1a2332;
    background: #fff; outline: none;
}
.sbc-select:focus, .sbc-input:focus { border-color: #1a2332; }
.sbc-btn-reset {
    padding: 7px 14px; background: #f1f5f9; border: 1px solid #e2e8f0;
    border-radius: 7px; font-size: 12px; cursor: pointer; color: #64748b;
    transition: all .2s;
}
.sbc-btn-reset:hover { background: #1a2332; color: #fff; border-color: #1a2332; }

/* Tableau */
.sbc-table {
    width: 100%; border-collapse: collapse;
    background: #fff; border-radius: 10px; overflow: hidden;
    border: 1px solid #e2e8f0; font-size: 12px;
}
.sbc-table thead tr { background: #1a2332; color: #fff; }
.sbc-table th { padding: 10px 12px; font-weight: 600; text-align: left; font-size: 11px; }
.sbc-table tbody tr { border-bottom: 1px solid #f1f5f9; transition: background .15s; cursor: pointer; }
.sbc-table tbody tr:hover { background: #f8fafc; }
.sbc-table td { padding: 10px 12px; color: #374151; }
.sbc-loading { text-align: center; padding: 40px; color: #94a3b8; font-size: 13px; }
.sbc-empty { text-align: center; padding: 30px; color: #94a3b8; }

/* Badges statut */
.sbc-badge {
    font-size: 10px; font-weight: 700;
    padding: 3px 9px; border-radius: 20px; display: inline-block;
}
.sbc-badge-brouillon  { background: #f1f5f9; color: #64748b; }
.sbc-badge-valide     { background: #dbeafe; color: #1d4ed8; }
.sbc-badge-vise       { background: #dcfce7; color: #15803d; }
.sbc-badge-execution  { background: #fef3c7; color: #b45309; }
.sbc-badge-solde      { background: #d1fae5; color: #065f46; }
.sbc-badge-envoye     { background:#dbeafe; color:#1d4ed8; }
.sbc-badge-rejete     { background:#fee2e2; color:#dc2626; }
.sbc-badge-rejete-def { background:#fca5a5; color:#7f1d1d; }

script:
// here root_element is provided by default

let adChart = null;
let adDonnees = [];
let sbcArticlesFaculte = [];

let adSelectChapitre = root_element.querySelector('#ad-chapitre');
let adSelectArticle  = root_element.querySelector('#ad-article');
let adBtnApply       = root_element.querySelector('#ad-btn-apply');
let adBtnReset       = root_element.querySelector('#ad-btn-reset');

// ── CHART.JS ──────────────────────────────────────
function adChargerChartJS(callback) {
    if (typeof Chart !== 'undefined') { callback(); return; }
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/chart.js';
    script.onload = callback;
    document.head.appendChild(script);
}

// ── Étape 0 : Faculté + chapitres filtrés ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name', 'chapitre'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rA) {
                        var articles = rA.message || [];
                        sbcArticlesFaculte = articles.map(function(a) { return a.name; });

                        var chapitresSet = {};
                        articles.forEach(function(a) { if (a.chapitre) chapitresSet[a.chapitre] = true; });
                        var chapitreNames = Object.keys(chapitresSet);

                        if (chapitreNames.length) {
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Chapitre',
                                    fields: ['name', 'code', 'intitule'],
                                    filters: [['name', 'in', chapitreNames]],
                                    limit_page_length: 0,
                                    order_by: 'code asc'
                                },
                                callback: function(rC) {
                                    (rC.message || []).forEach(function(c) {
                                        let opt = document.createElement('option');
                                        opt.value = c.name;
                                        opt.textContent = (c.code || c.name) + ' - ' + c.intitule;
                                        adSelectChapitre.appendChild(opt);
                                    });
                                }
                            });
                        }
                    }
                });
            }
        });
    }
});

// ── CHANGEMENT CHAPITRE → ARTICLES ───────────────
adSelectChapitre.addEventListener('change', function() {
    let chapVal = this.value;
    adSelectArticle.innerHTML = '<option value="">Tous les articles</option>';
    if (chapVal) {
        var filters = [['chapitre', '=', chapVal]];
        if (sbcArticlesFaculte.length) filters.push(['name', 'in', sbcArticlesFaculte]);
        frappe.call({
            method: 'frappe.client.get_list',
            args: { doctype: 'Article', filters: filters, fields: ['name', 'code_article', 'intitule_article'], limit_page_length: 0, order_by: 'code_article asc' },
            callback: function(r) {
                (r.message || []).forEach(function(a) {
                    let opt = document.createElement('option');
                    opt.value = a.name;
                    opt.textContent = (a.code_article || a.name) + ' - ' + a.intitule_article;
                    adSelectArticle.appendChild(opt);
                });
            }
        });
    }
});

// ── BOUTON APPLIQUER ──────────────────────────────
adBtnApply.addEventListener('click', function() {
    let chapVal    = adSelectChapitre.value;
    let articleVal = adSelectArticle.value;
    let dateDebut  = root_element.querySelector('#ad-date-debut').value;
    let dateFin    = root_element.querySelector('#ad-date-fin').value;

    let filters = [];
    if (chapVal)    filters.push(['chapitre',    '=',  chapVal]);
    if (articleVal) filters.push(['article',     '=',  articleVal]);
    else if (sbcArticlesFaculte.length) filters.push(['article', 'in', sbcArticlesFaculte]);
    if (dateDebut)  filters.push(['date_depense', '>=', dateDebut]);
    if (dateFin)    filters.push(['date_depense', '<=', dateFin]);

    if (!chapVal) {
        root_element.querySelector('#ad-chart-section').style.display = 'none';
        if (adChart) { adChart.destroy(); adChart = null; }
    }

    root_element.querySelector('#ad-table-body').innerHTML =
        '<tr><td colspan="6" class="loading">⏳ Chargement...</td></tr>';

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Depense Interne',
            fields: ['name', 'numero_interne', 'date_depense', 'chapitre', 'intitule_chapitre', 'article', 'code_article', 'intitule_article', 'type_depense', 'status', 'montant_total'],
            filters: filters,
            limit_page_length: 0,
            order_by: 'date_depense desc'
        },
        callback: function(r) {
            if (!r.message || !r.message.length) { adAfficherVide(chapVal); return; }

            let resultats = r.message;
            resultats.sort(function(a, b) { return new Date(b.date_depense) - new Date(a.date_depense); });
            adDonnees = resultats;

            let totalDepense = resultats.reduce(function(s, d) { return s + (d.montant_total || 0); }, 0);
            adChargerChartJS(function() {
                adMajStats(adDonnees);
                adMajTableau(adDonnees);
                if (chapVal) adChargerBudgetEtGraphique(chapVal, articleVal, totalDepense);
            });
        }
    });
});

// ── CHARGER BUDGET → GRAPHE ───────────────────────
function adChargerBudgetEtGraphique(chapVal, articleVal, totalDepense) {
    var filters = articleVal
        ? [['article', '=', articleVal]]
        : (sbcArticlesFaculte.length ? [['article', 'in', sbcArticlesFaculte]] : []);

    frappe.call({
        method: 'frappe.client.get_list',
        args: { doctype: 'Budget Article', filters: filters, fields: ['montant'], limit_page_length: 0 },
        callback: function(rB) {
            let budget  = (rB.message || []).reduce(function(s, b) { return s + (b.montant || 0); }, 0);
            let restant = Math.max(budget - totalDepense, 0);
            adAfficherGraphique(totalDepense, restant, budget);
        }
    });
}

function adAfficherGraphique(depense, restant, budget) {
    let section = root_element.querySelector('#ad-chart-section');
    let ctx     = root_element.querySelector('#ad-depensesChart');
    if (!ctx) return;

    section.style.display = 'block';
    let pct = budget > 0 ? Math.round(depense / budget * 100) : 0;

    root_element.querySelector('#ad-chart-title').textContent =
        'Budget : ' + adFmt(budget) + '   |   Dépensé : ' + adFmt(depense) + '   |   ' + pct + '% consommé';

    if (adChart) { try { adChart.destroy(); } catch(e) {} adChart = null; }

    ctx.parentElement.style.position = 'relative';
    ctx.parentElement.style.height   = '320px';

    adChart = new Chart(ctx.getContext('2d'), {
        type: 'pie',
        data: {
            labels: ['Dépensé', 'Restant'],
            datasets: [{
                data: [depense, restant],
                backgroundColor: ['#131246', '#1c3b22'],
                hoverBackgroundColor: ['#1b1a6e', '#295733'],
                borderWidth: 2,
                borderColor: '#ffffff'
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: { position: 'bottom', labels: { padding: 20, font: { size: 13 }, usePointStyle: true } },
                tooltip: {
                    callbacks: {
                        label: function(context) {
                            let p = budget > 0 ? ((context.parsed / budget) * 100).toFixed(1) : 0;
                            return ' ' + adFmt(context.parsed) + ' (' + p + '%)';
                        }
                    }
                }
            }
        }
    });
}

function adMajStats(donnees) {
    let total    = donnees.reduce(function(s, d) { return s + (d.montant_total || 0); }, 0);
    let articles = new Set(donnees.map(function(d) { return d.article; })).size;
    let moyenne  = donnees.length ? total / donnees.length : 0;
    let max      = donnees.length ? Math.max.apply(null, donnees.map(function(d) { return d.montant_total || 0; })) : 0;
    root_element.querySelector('#ad-total-depenses').textContent  = adFmt(total);
    root_element.querySelector('#ad-nb-articles').textContent     = articles;
    root_element.querySelector('#ad-depense-moyenne').textContent = adFmt(moyenne);
    root_element.querySelector('#ad-max-depense').textContent     = adFmt(max);
}

function adMajTableau(donnees) {
    let tbody = root_element.querySelector('#ad-table-body');
    tbody.innerHTML = '';
    donnees.forEach(function(d) {
        let tr = document.createElement('tr');
        tr.innerHTML =
            '<td><strong>' + (d.chapitre || '—') + '</strong></td>' +
            '<td>' + (d.intitule_chapitre || '—') + '</td>' +
            '<td><strong>' + (d.code_article || d.article || '—') + '</strong></td>' +
            '<td>' + (d.intitule_article || '—') + '</td>' +
            '<td><strong>' + adFmt(d.montant_total || 0) + '</strong></td>' +
            '<td>' + adFmtDate(d.date_depense) + '</td>';
        tbody.appendChild(tr);
    });
}

function adAfficherVide(chapVal) {
    root_element.querySelector('#ad-table-body').innerHTML =
        '<tr><td colspan="6" class="no-data"><div class="no-data-icon">📭</div><div>Aucune dépense ne correspond à vos critères</div></td></tr>';
    root_element.querySelector('#ad-total-depenses').textContent  = '0 DA';
    root_element.querySelector('#ad-nb-articles').textContent     = '0';
    root_element.querySelector('#ad-depense-moyenne').textContent = '0 DA';
    root_element.querySelector('#ad-max-depense').textContent     = '0 DA';
    if (!chapVal) root_element.querySelector('#ad-chart-section').style.display = 'none';
    if (adChart) { adChart.destroy(); adChart = null; }
}

adBtnReset.addEventListener('click', function() {
    adSelectChapitre.value    = '';
    adSelectArticle.innerHTML = '<option value="">Tous les articles</option>';
    root_element.querySelector('#ad-date-debut').value = '';
    root_element.querySelector('#ad-date-fin').value   = '';
    root_element.querySelector('#ad-total-depenses').textContent  = '0 DA';
    root_element.querySelector('#ad-nb-articles').textContent     = '0';
    root_element.querySelector('#ad-depense-moyenne').textContent = '0 DA';
    root_element.querySelector('#ad-max-depense').textContent     = '0 DA';
    root_element.querySelector('#ad-chart-section').style.display = 'none';
    root_element.querySelector('#ad-table-body').innerHTML =
        '<tr><td colspan="6" class="loading">Sélectionnez des filtres et cliquez sur Appliquer</td></tr>';
    if (adChart) { adChart.destroy(); adChart = null; }
});

function adFmt(n) {
    return new Intl.NumberFormat('fr-DZ', { style: 'currency', currency: 'DZD', minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(n || 0);
}
function adFmtDate(s) {
    if (!s) return '—';
    return new Intl.DateTimeFormat('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(s));
}

style:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; }

.container-widget { max-width: 100%; background: #fff; border-radius: 10px; box-shadow: 0 3px 12px rgba(0,0,0,0.1); overflow: hidden; }

.header { background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%); color: #fff; text-align: center; padding: 25px 15px; }
.header h1 { font-size: 26px; margin-bottom: 5px; color: #fff; }
.header p { font-size: 14px; opacity: 0.85; }

.filters-section { padding: 25px 20px; background: #f8f9fa; border-bottom: 1px solid #e9ecef; }
.filters-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 20px; margin-bottom: 15px; }
.filter-group { display: flex; flex-direction: column; }
.filter-group label { font-weight: 600; margin-bottom: 6px; color: #495057; font-size: 14px; }
.filter-group select, .filter-group input { padding: 10px 12px; border: 2px solid #e9ecef; border-radius: 6px; font-size: 14px; transition: border-color 0.3s; background: #fff; }
.filter-group select:focus, .filter-group input:focus { border-color: #667eea; outline: none; }

.btn-apply {  background: linear-gradient(135deg, #1a2332 0%, #2d3748 100%); color: #fff; border: none; padding: 10px 25px; border-radius: 6px; font-weight: 600; cursor: pointer; transition: all 0.2s; }
.btn-apply:hover { transform: translateY(-2px); box-shadow: 0 4px 10px rgba(102,126,234,0.4); }
.ad-btn-reset-custom {  background: #fff; color: #1a2332;border: 2px solid #1a2332; padding: 10px 25px; border-radius: 6px; font-weight: 600; cursor: pointer; margin-left: 10px; transition: all 0.2s; }
.ad-btn-reset-custom:hover {background: #1a2332; color: #fff; }

.stats-section { padding: 25px 20px; display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 20px; }
.stat-card { padding: 18px; border-radius: 8px; color: #fff; text-align: center; background: linear-gradient(135deg, #101324ee 0%, #10132465 100%); }

.stat-card.green  { background: linear-gradient(135deg, #000000 0%, #36343441 100%); }
.stat-card.orange { background: linear-gradient(135deg, #1c3b22d5 0%, #534a2da2 100%); }
.stat-card.red    { background: linear-gradient(135deg, #131246e0 0%, #13124683 100%); }

.stat-label { font-size: 12px; opacity: 0.9; text-transform: uppercase; margin-bottom: 8px; }
.stat-value { font-size: 28px; font-weight: bold; }

.chart-section { padding: 25px 20px; border-bottom: 1px solid #e9ecef; }
.chart-container { position: relative; height: 320px; }

.table-section { padding: 20px; }
.table-wrapper { overflow-x: auto; border-radius: 8px; border: 1px solid #e9ecef; }
table { width: 100%; border-collapse: collapse; }
thead { background: #f8f9fa; }
th, td { padding: 12px 15px; text-align: left; color: #495057; }
th { font-weight: 600; font-size: 13px; border-bottom: 2px solid #e9ecef; }
td { border-bottom: 1px solid #f1f3f5; }
tbody tr:hover { background: #f8f9fa; }

.loading, .no-data { text-align: center; padding: 35px; color: #6c757d; font-size: 14px; }
.no-data-icon { font-size: 40px; margin-bottom: 12px; }

@media (max-width: 768px) {
    .filters-grid, .stats-section { grid-template-columns: 1fr; }
    .ad-btn-reset-custom { margin-left: 0; margin-top: 10px; display: block; }
}

script:
// here root_element is provided by default

var tousLesEnseignants = [];

function fmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function afficherTableau(liste) {
    var tbody = root_element.querySelector('#se-tbody');
    if (!liste.length) {
        tbody.innerHTML = '<tr><td colspan="9" class="se-empty">📭 Aucun enseignant trouvé</td></tr>';
        return;
    }
    tbody.innerHTML = liste.map(function(e) {
        var nbMissions = e.nb_missions || 0;
        var totalPaye  = e.total_paye  || 0;
        var statut = nbMissions > 0
            ? '<span class="se-badge se-badge-actif">Actif</span>'
            : '<span class="se-badge se-badge-inactif">Aucune mission</span>';
        return '<tr onclick="window.location=\'/app/enseignant/' + e.name + '\'">' +
            '<td class="se-matricule">' + (e.matricule     || '—') + '</td>' +
            '<td class="se-nom">'       + (e.nom_prenom    || '—') + '</td>' +
            '<td>'                      + (e.faculte       || '—') + '</td>' +
            '<td>'                      + (e.grade         || '—') + '</td>' +
            '<td>'                      + (e.type_compte   || '—') + '</td>' +
            '<td style="font-family:monospace">' + (e.numero_compte || '—') + '</td>' +
            '<td style="text-align:right;font-weight:700">' + nbMissions + '</td>' +
            '<td class="se-montant">'   + fmt(totalPaye) + '</td>' +
            '<td style="text-align:center">' + statut + '</td>' +
        '</tr>';
    }).join('');
}

function majKPIs(liste) {
    var totalMissions = liste.reduce(function(s, e) { return s + (e.nb_missions || 0); }, 0);
    var totalMontant  = liste.reduce(function(s, e) { return s + (e.total_paye  || 0); }, 0);
    root_element.querySelector('#kpi-nb-ens').textContent         = liste.length;
    root_element.querySelector('#kpi-total-missions').textContent = totalMissions;
    root_element.querySelector('#kpi-total-montant').textContent  = fmt(totalMontant);
    root_element.querySelector('#se-sub').textContent             = liste.length + ' enseignants enregistrés';
}

root_element.querySelector('#se-search').addEventListener('input', function() {
    var q = this.value.toLowerCase();
    var filtres = tousLesEnseignants.filter(function(e) {
        return (e.nom_prenom || '').toLowerCase().includes(q) ||
               (e.matricule  || '').toLowerCase().includes(q) ||
               (e.faculte    || '').toLowerCase().includes(q);
    });
    afficherTableau(filtres);
});

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Enseignants filtrés par faculté ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Enseignant',
                fields: ['name', 'matricule', 'nom_prenom', 'faculte', 'grade', 'type_compte', 'numero_compte'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit: 0,
                order_by: 'nom_prenom asc'
            },
            callback: function(rE) {
                tousLesEnseignants = (rE.message || []).map(function(e) {
                    e.nb_missions = 0;
                    e.total_paye  = 0;
                    return e;
                });

                majKPIs(tousLesEnseignants);
                afficherTableau(tousLesEnseignants);

                if (!tousLesEnseignants.length) return;

                var statsParEns    = {};
                var appelsTermines = 0;
                var totalAppels    = 2;

                function fusionner() {
                    appelsTermines++;
                    if (appelsTermines === totalAppels) {
                        tousLesEnseignants = tousLesEnseignants.map(function(e) {
                            var stats = statsParEns[e.name] || { nb: 0, total: 0 };
                            e.nb_missions = stats.nb;
                            e.total_paye  = stats.total;
                            return e;
                        });
                        tousLesEnseignants.sort(function(a, b) { return b.total_paye - a.total_paye; });
                        majKPIs(tousLesEnseignants);
                        afficherTableau(tousLesEnseignants);
                    }
                }

                function ajouterStats(beneficiaires) {
                    (beneficiaires || []).forEach(function(b) {
                        if (b.type_personne === 'Enseignant' && b.personne) {
                            if (!statsParEns[b.personne]) statsParEns[b.personne] = { nb: 0, total: 0 };
                            statsParEns[b.personne].nb++;
                            statsParEns[b.personne].total += (b.montant || 0);
                        }
                    });
                }

                // ── Étape 2a : Depense Interne Frais Mission ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Depense Interne',
                        fields: ['name'],
                        filters: [['type_depense', '=', 'Frais Mission'], ['status', '=', 'Régularisé']],
                        limit: 0
                    },
                    callback: function(rD) {
                        var depenses = rD.message || [];
                        if (!depenses.length) { fusionner(); return; }
                        var pending = depenses.length;
                        depenses.forEach(function(d) {
                            frappe.call({
                                method: 'frappe.client.get',
                                args: { doctype: 'Depense Interne', name: d.name },
                                callback: function(res) {
                                    if (res.message) ajouterStats(res.message.beneficiaires);
                                    pending--;
                                    if (pending === 0) fusionner();
                                }
                            });
                        });
                    }
                });

                // ── Étape 2b : Fiche Budgetaire Dépense Visé CF ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Fiche Budgetaire',
                        fields: ['name'],
                        filters: [
                            ['type_article', '=', 'A priori'],
                            ['type_fiche',   '=', 'Dépense'],
                            ['status',       '=', 'Visé CF']
                        ],
                        limit: 0
                    },
                    callback: function(rF) {
                        var fiches = rF.message || [];
                        if (!fiches.length) { fusionner(); return; }
                        var pending = fiches.length;
                        fiches.forEach(function(f) {
                            frappe.call({
                                method: 'frappe.client.get',
                                args: { doctype: 'Fiche Budgetaire', name: f.name },
                                callback: function(res) {
                                    if (res.message) ajouterStats(res.message.beneficiaires);
                                    pending--;
                                    if (pending === 0) fusionner();
                                }
                            });
                        });
                    }
                });
            }
        });
    }
});

