script:
// here root_element is provided by default

var tousLePersonnel = [];

function fmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function afficherTableau(liste) {
    var tbody = root_element.querySelector('#spa-tbody');
    if (!liste.length) {
        tbody.innerHTML = '<tr><td colspan="10" class="spa-empty">📭 Aucun personnel trouvé</td></tr>';
        return;
    }
    tbody.innerHTML = liste.map(function(e) {
        var nbMissions = e.nb_missions || 0;
        var totalPaye  = e.total_paye  || 0;
        var statut = nbMissions > 0
            ? '<span class="spa-badge spa-badge-actif">Actif</span>'
            : '<span class="spa-badge spa-badge-inactif">Aucune mission</span>';
        return '<tr onclick="window.location=\'/app/personnel-administratif/' + e.name + '\'">' +
            '<td class="spa-matricule">' + (e.matricule    || '—') + '</td>' +
            '<td class="spa-nom">'       + (e.nom_prenom   || '—') + '</td>' +
            '<td>'                       + (e.faculte      || '—') + '</td>' +
            '<td>'                       + (e.grade        || '—') + '</td>' +
            '<td>'                       + (e.service      || '—') + '</td>' +
            '<td>'                       + (e.type_compte  || '—') + '</td>' +
            '<td style="font-family:monospace">' + (e.numero_compte || '—') + '</td>' +
            '<td style="text-align:right;font-weight:700">' + nbMissions + '</td>' +
            '<td class="spa-montant">'   + fmt(totalPaye) + '</td>' +
            '<td style="text-align:center">' + statut + '</td>' +
        '</tr>';
    }).join('');
}

function majKPIs(liste) {
    var totalMissions = liste.reduce(function(s, e) { return s + (e.nb_missions || 0); }, 0);
    var totalMontant  = liste.reduce(function(s, e) { return s + (e.total_paye  || 0); }, 0);
    root_element.querySelector('#spa-kpi-nb').textContent       = liste.length;
    root_element.querySelector('#spa-kpi-missions').textContent = totalMissions;
    root_element.querySelector('#spa-kpi-montant').textContent  = fmt(totalMontant);
    root_element.querySelector('#spa-sub').textContent          = liste.length + ' personnels enregistrés';
}

root_element.querySelector('#spa-search').addEventListener('input', function() {
    var q = this.value.toLowerCase();
    var filtres = tousLePersonnel.filter(function(e) {
        return (e.nom_prenom || '').toLowerCase().includes(q) ||
               (e.matricule  || '').toLowerCase().includes(q) ||
               (e.service    || '').toLowerCase().includes(q);
    });
    afficherTableau(filtres);
});

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Personnel Administratif filtré par faculté ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Personnel Administratif',
                fields: ['name', 'matricule', 'nom_prenom', 'faculte', 'grade', 'service', 'type_compte', 'numero_compte'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit: 0,
                order_by: 'nom_prenom asc'
            },
            callback: function(rE) {
                tousLePersonnel = (rE.message || []).map(function(e) {
                    e.nb_missions = 0; e.total_paye = 0; return e;
                });
                majKPIs(tousLePersonnel);
                afficherTableau(tousLePersonnel);

                if (!tousLePersonnel.length) return;

                var personnelNames = tousLePersonnel.map(function(e) { return e.name; });
                var statsParPerso  = {};
                var appelsTermines = 0;
                var totalAppels    = 2;

                function fusionner() {
                    appelsTermines++;
                    if (appelsTermines === totalAppels) {
                        tousLePersonnel = tousLePersonnel.map(function(e) {
                            var s = statsParPerso[e.name] || { nb: 0, total: 0 };
                            e.nb_missions = s.nb;
                            e.total_paye  = s.total;
                            return e;
                        });
                        tousLePersonnel.sort(function(a, b) { return b.total_paye - a.total_paye; });
                        majKPIs(tousLePersonnel);
                        afficherTableau(tousLePersonnel);
                    }
                }

                function ajouterDepenseInterne(beneficiaires) {
                    (beneficiaires || []).forEach(function(b) {
                        if (b.type_personne === 'Personnel Administratif' && b.personne) {
                            if (!statsParPerso[b.personne]) statsParPerso[b.personne] = { nb: 0, total: 0 };
                            statsParPerso[b.personne].nb++;
                            statsParPerso[b.personne].total += (b.montant || 0);
                        }
                    });
                }

                function ajouterFraisMission(beneficiaires) {
                    (beneficiaires || []).forEach(function(b) {
                        if (b.type_personne_doctype === 'Personnel Administratif' && b.personne) {
                            if (!statsParPerso[b.personne]) statsParPerso[b.personne] = { nb: 0, total: 0 };
                            statsParPerso[b.personne].nb++;
                            statsParPerso[b.personne].total += (b.montant_mission || 0);
                        }
                    });
                }

                // ── Étape 2a : Depense Interne Frais Mission ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Depense Interne',
                        fields: ['name'],
                        filters: [['type_depense', '=', 'Frais Mission'], ['status', '=', 'Régularisé']],
                        limit: 0
                    },
                    callback: function(rD) {
                        var depenses = rD.message || [];
                        if (!depenses.length) { fusionner(); return; }
                        var pending = depenses.length;
                        depenses.forEach(function(d) {
                            frappe.call({
                                method: 'frappe.client.get',
                                args: { doctype: 'Depense Interne', name: d.name },
                                callback: function(res) {
                                    if (res.message) ajouterDepenseInterne(res.message.beneficiaires);
                                    pending--;
                                    if (pending === 0) fusionner();
                                }
                            });
                        });
                    }
                });

                // ── Étape 2b : Fiche Budgetaire Frais Mission A priori ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Fiche Budgetaire',
                        fields: ['name', 'frais_mission_apriori'],
                        filters: [
                            ['type_article',            '=', 'A priori'],
                            ['type_fiche',              '=', 'Dépense'],
                            ['status',                  '=', 'Visé CF'],
                            ['type_engagement_apriori', '=', 'Frais Mission']
                        ],
                        limit: 0
                    },
                    callback: function(rF) {
                        var fiches = (rF.message || []).filter(function(f) { return f.frais_mission_apriori; });
                        if (!fiches.length) { fusionner(); return; }
                        var pending = fiches.length;
                        fiches.forEach(function(f) {
                            frappe.call({
                                method: 'frappe.client.get',
                                args: { doctype: 'Frais Mission', name: f.frais_mission_apriori },
                                callback: function(res) {
                                    if (res.message) ajouterFraisMission(res.message.table_beneficiaires);
                                    pending--;
                                    if (pending === 0) fusionner();
                                }
                            });
                        });
                    }
                });
            }
        });
    }
});

