.spa-empty   { text-align: center; padding: 32px; color: #94a3b8; font-size: 13px; }

script:
// here root_element is provided by default

// Guard : exécuter une seule fois par session de page
if (window.tstDejaCharge) { return; }
window.tstDejaCharge = true;

var TST_SEUIL    = 40;
var TST_DUREE    = 6000;
var TST_DECALAGE = 600;

var tstContainer = document.getElementById('tst-container-global');
if (!tstContainer) {
    tstContainer = document.createElement('div');
    tstContainer.id = 'tst-container-global';
    tstContainer.style.cssText =
        'position:fixed;top:70px;right:20px;z-index:99999;' +
        'display:flex;flex-direction:column;gap:10px;width:360px;';
    document.body.appendChild(tstContainer);
}

if (!document.getElementById('tst-style')) {
    var style = document.createElement('style');
    style.id = 'tst-style';
    style.textContent =
        '.tst-item{background:#fff;border-radius:10px;box-shadow:0 8px 24px rgba(0,0,0,.15);border-left:5px solid #ef4444;padding:14px 16px 10px;overflow:hidden;animation:tst-in .4s ease forwards;font-family:Segoe UI,sans-serif;}' +
        '.tst-item.tst-out{animation:tst-out .4s ease forwards;}' +
        '@keyframes tst-in{from{opacity:0;transform:translateX(110%)}to{opacity:1;transform:translateX(0)}}' +
        '@keyframes tst-out{from{opacity:1;transform:translateX(0)}to{opacity:0;transform:translateX(110%)}}' +
        '.tst-top{display:flex;align-items:flex-start;justify-content:space-between;gap:10px;margin-bottom:8px;}' +
        '.tst-left{display:flex;align-items:flex-start;gap:10px;flex:1;}' +
        '.tst-emoji{font-size:20px;flex-shrink:0;margin-top:1px;}' +
        '.tst-title{font-size:13px;font-weight:700;color:#ef4444;margin-bottom:3px;}' +
        '.tst-msg{font-size:12px;color:#374151;line-height:1.4;}' +
        '.tst-right{display:flex;align-items:center;gap:8px;flex-shrink:0;}' +
        '.tst-pct{font-size:20px;font-weight:800;color:#ef4444;font-family:monospace;}' +
        '.tst-close{background:none;border:none;cursor:pointer;color:#9ca3af;font-size:16px;padding:0;line-height:1;}' +
        '.tst-close:hover{color:#374151;}' +
        '.tst-progress-wrap{height:4px;background:#fee2e2;border-radius:99px;overflow:hidden;}' +
        '.tst-progress-bar{height:100%;background:#ef4444;border-radius:99px;width:100%;}';
    document.head.appendChild(style);
}

function tstFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function tstAfficher(articleName, pct, depense, budget, index) {
    setTimeout(function() {
        var toast = document.createElement('div');
        toast.className = 'tst-item';
        toast.innerHTML =
            '<div class="tst-top">' +
                '<div class="tst-left">' +
                    '<span class="tst-emoji">🚨</span>' +
                    '<div>' +
                        '<div class="tst-title">Alerte Budget — ' + articleName + '</div>' +
                        '<div class="tst-msg">' +
                            'Dépensé : <strong>' + tstFmt(depense) + '</strong> / Budget : <strong>' + tstFmt(budget) + '</strong>' +
                        '</div>' +
                    '</div>' +
                '</div>' +
                '<div class="tst-right">' +
                    '<span class="tst-pct">' + pct + '%</span>' +
                    '<button class="tst-close" title="Fermer">✕</button>' +
                '</div>' +
            '</div>' +
            '<div class="tst-progress-wrap"><div class="tst-progress-bar"></div></div>';

        tstContainer.appendChild(toast);
        toast.querySelector('.tst-close').addEventListener('click', function() { tstFermer(toast); });

        var bar = toast.querySelector('.tst-progress-bar');
        var timer = null;

        function demarrer(duree) {
            bar.style.transition = 'width ' + duree + 'ms linear';
            bar.style.width = '0%';
            timer = setTimeout(function() { tstFermer(toast); }, duree);
        }
        setTimeout(function() { demarrer(TST_DUREE); }, 50);
        toast.addEventListener('mouseenter', function() { clearTimeout(timer); bar.style.transition = 'none'; });
        toast.addEventListener('mouseleave', function() {
            var largeur = parseFloat(getComputedStyle(bar).width);
            var parentW = bar.parentElement.offsetWidth;
            var restant = parentW > 0 ? (largeur / parentW) * TST_DUREE : TST_DUREE;
            demarrer(Math.max(restant, 500));
        });
    }, index * TST_DECALAGE);
}

function tstFermer(toast) {
    toast.classList.add('tst-out');
    setTimeout(function() { if (toast.parentNode) toast.parentNode.removeChild(toast); }, 400);
}

var tstMap = {};

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Années budgétaires de la faculté ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // ── Étape 2 : Articles de ces années ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles = (rArt.message || []).map(function(a) { return a.name; });
                        if (!articles.length) return;

                        // ── Étape 3 : Budget Article ──
                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Budget Article',
                                fields: ['article', 'montant'],
                                filters: [['article', 'in', articles]],
                                limit_page_length: 0
                            },
                            callback: function(r1) {
                                (r1.message || []).forEach(function(b) {
                                    if (!tstMap[b.article]) tstMap[b.article] = { budget: 0, depense: 0 };
                                    tstMap[b.article].budget += (b.montant || 0);
                                });

                                // ── Étape 4 : Depense Interne Régularisé ──
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Depense Interne',
                                        fields: ['article', 'montant_total'],
                                        filters: [['status', '=', 'Régularisé'], ['article', 'in', articles]],
                                        limit_page_length: 0
                                    },
                                    callback: function(r2) {
                                        (r2.message || []).forEach(function(d) {
                                            if (!d.article) return;
                                            if (!tstMap[d.article]) tstMap[d.article] = { budget: 0, depense: 0 };
                                            tstMap[d.article].depense += (d.montant_total || 0);
                                        });

                                        // ── Étape 5 : Fiche Budgetaire Dépense Visé CF ──
                                        frappe.call({
                                            method: 'frappe.client.get_list',
                                            args: {
                                                doctype: 'Fiche Budgetaire',
                                                fields: ['article', 'montant_operation'],
                                                filters: [
                                                    ['type_fiche', '=', 'Dépense'],
                                                    ['status',     '=', 'Visé CF'],
                                                    ['article',    'in', articles]
                                                ],
                                                limit_page_length: 0
                                            },
                                            callback: function(r3) {
                                                (r3.message || []).forEach(function(f) {
                                                    if (!f.article) return;
                                                    if (!tstMap[f.article]) tstMap[f.article] = { budget: 0, depense: 0 };
                                                    tstMap[f.article].depense += (f.montant_operation || 0);
                                                });

                                                // Calculer et afficher
                                                var alertes = [];
                                                Object.keys(tstMap).forEach(function(articleName) {
                                                    var d = tstMap[articleName];
                                                    if (d.budget <= 0) return;
                                                    var pct = Math.round(d.depense / d.budget * 100);
                                                    if (pct >= TST_SEUIL) {
                                                        alertes.push({ article: articleName, pct: pct, depense: d.depense, budget: d.budget });
                                                    }
                                                });

                                                alertes.sort(function(a, b) { return b.pct - a.pct; });
                                                alertes.forEach(function(a, i) {
                                                    tstAfficher(a.article, a.pct, a.depense, a.budget, i);
                                                });
                                            }
                                        });
                                    }
                                });
                            }
                        });
                    }
                });
            }
        });
    }
});

