script:
// ══════════════════════════════════════════
// JS
// ══════════════════════════════════════════
let adChart   = null;
let adDonnees = [];
let adArticlesDeLaFaculte = [];

let adSelectChapitre = root_element.querySelector('#ad-chapitre');
let adSelectArticle  = root_element.querySelector('#ad-article');
let adBtnApply       = root_element.querySelector('#ad-btn-apply');
let adBtnReset       = root_element.querySelector('#ad-btn-reset');

// ── CHART.JS ──────────────────────────────
function adChargerChartJS(callback) {
    if (typeof Chart !== 'undefined') { callback(); return; }
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/chart.js';
    script.onload = callback;
    document.head.appendChild(script);
}

// ── Étape 0 : Faculté + articles + chapitres ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name', 'code_article', 'intitule_article', 'type', 'chapitre'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0,
                        order_by: 'code_article asc'
                    },
                    callback: function(rA) {
                        var articles = rA.message || [];
                        adArticlesDeLaFaculte = articles.map(function(a) { return a.name; });

                        // Chapitres uniques
                        var chapitresSet = {};
                        articles.forEach(function(a) { if (a.chapitre) chapitresSet[a.chapitre] = true; });
                        var chapitreNames = Object.keys(chapitresSet);

                        if (chapitreNames.length) {
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Chapitre',
                                    fields: ['name', 'code', 'intitule'],
                                    filters: [['name', 'in', chapitreNames]],
                                    limit_page_length: 0,
                                    order_by: 'code asc'
                                },
                                callback: function(rC) {
                                    (rC.message || []).forEach(function(c) {
                                        let opt = document.createElement('option');
                                        opt.value = c.name;
                                        opt.textContent = (c.code || c.name) + ' - ' + c.intitule;
                                        adSelectChapitre.appendChild(opt);
                                    });
                                }
                            });
                        }
                    }
                });
            }
        });
    }
});

// ── CHANGEMENT CHAPITRE → ARTICLES ─────────
adSelectChapitre.addEventListener('change', function() {
    let chapVal = this.value;
    adSelectArticle.innerHTML = '<option value="">Tous les articles</option>';
    if (chapVal) {
        var filters = [['chapitre', '=', chapVal]];
        if (adArticlesDeLaFaculte.length) filters.push(['name', 'in', adArticlesDeLaFaculte]);
        frappe.call({
            method: 'frappe.client.get_list',
            args: { doctype: 'Article', filters: filters, fields: ['name', 'code_article', 'intitule_article', 'type'], limit_page_length: 0, order_by: 'code_article asc' },
            callback: function(r) {
                (r.message || []).forEach(function(a) {
                    let opt = document.createElement('option');
                    opt.value = a.name;
                    opt.textContent = (a.code_article || a.name) + ' - ' + a.intitule_article + ' (' + (a.type || '?') + ')';
                    adSelectArticle.appendChild(opt);
                });
            }
        });
    }
});

// ── BOUTON APPLIQUER ───────────────────────
adBtnApply.addEventListener('click', function() {
    let chapVal    = adSelectChapitre.value;
    let articleVal = adSelectArticle.value;
    let dateDebut  = root_element.querySelector('#ad-date-debut').value;
    let dateFin    = root_element.querySelector('#ad-date-fin').value;

    root_element.querySelector('#ad-table-body').innerHTML =
        '<tr><td colspan="7" class="loading">⏳ Chargement...</td></tr>';
    root_element.querySelector('#ad-chart-section').style.display = 'none';
    if (adChart) { adChart.destroy(); adChart = null; }

    let resultatsApriori     = [];
    let resultatsAposteriori = [];
    let chargements = 0;

    function verifierFusion() {
        chargements++;
        if (chargements === 2) {
            fusionnerEtAfficher(resultatsApriori, resultatsAposteriori, chapVal, articleVal);
        }
    }

    // ── SOURCE 1 : Fiche Budgetaire (A priori, Visé CF) ──
    let filtresFB = [['type_fiche', '=', 'Dépense'], ['status', '=', 'Visé CF']];
    if (chapVal)    filtresFB.push(['chapitre', '=', chapVal]);
    if (articleVal) filtresFB.push(['article',  '=', articleVal]);
    else if (adArticlesDeLaFaculte.length) filtresFB.push(['article', 'in', adArticlesDeLaFaculte]);
    if (dateDebut)  filtresFB.push(['date_signature_doyen', '>=', dateDebut]);
    if (dateFin)    filtresFB.push(['date_signature_doyen', '<=', dateFin]);

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Fiche Budgetaire',
            fields: ['name', 'chapitre', 'article', 'code_article', 'intitule_article', 'intitule_chapitre', 'date_signature_doyen', 'status', 'montant_operation'],
            filters: filtresFB,
            limit_page_length: 0,
            order_by: 'date_signature_doyen desc'
        },
        callback: function(r) {
            (r.message || []).forEach(function(doc) {
                resultatsApriori.push({
                    source:              'apriori',
                    name:                doc.name,
                    chapitre:            doc.chapitre,
                    intitule_chapitre:   doc.intitule_chapitre || '—',
                    article:             doc.article,
                    code_article:        doc.code_article || doc.article,
                    intitule_article:    doc.intitule_article || '—',
                    montant_apriori:     doc.montant_operation || 0,
                    montant_aposteriori: 0,
                    date:                doc.date_signature_doyen
                });
            });
            verifierFusion();
        }
    });

    // ── SOURCE 2 : Depense Interne (A posteriori, Régularisé) ──
    let filtresDI = [['status', '=', 'Régularisé']];
    if (chapVal)    filtresDI.push(['chapitre', '=', chapVal]);
    if (articleVal) filtresDI.push(['article',  '=', articleVal]);
    else if (adArticlesDeLaFaculte.length) filtresDI.push(['article', 'in', adArticlesDeLaFaculte]);
    if (dateDebut)  filtresDI.push(['date_depense', '>=', dateDebut]);
    if (dateFin)    filtresDI.push(['date_depense', '<=', dateFin]);

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Depense Interne',
            fields: ['name', 'chapitre', 'article', 'code_article', 'intitule_article', 'intitule_chapitre', 'date_depense', 'status', 'montant_total'],
            filters: filtresDI,
            limit_page_length: 0,
            order_by: 'date_depense desc'
        },
        callback: function(r) {
            (r.message || []).forEach(function(doc) {
                resultatsAposteriori.push({
                    source:              'aposteriori',
                    name:                doc.name,
                    chapitre:            doc.chapitre,
                    intitule_chapitre:   doc.intitule_chapitre || '—',
                    article:             doc.article,
                    code_article:        doc.code_article || doc.article,
                    intitule_article:    doc.intitule_article || '—',
                    montant_apriori:     0,
                    montant_aposteriori: doc.montant_total || 0,
                    date:                doc.date_depense
                });
            });
            verifierFusion();
        }
    });
});

// ── FUSION + AFFICHAGE ─────────────────────
function fusionnerEtAfficher(apriori, aposteriori, chapVal, articleVal) {
    let donnees = [];

    apriori.forEach(function(d) {
        donnees.push({
            chapitre: d.chapitre, intitule_chapitre: d.intitule_chapitre,
            article: d.article, code_article: d.code_article, intitule_article: d.intitule_article,
            montant_apriori: d.montant_apriori, montant_aposteriori: 0, date: d.date
        });
    });

    aposteriori.forEach(function(d) {
        donnees.push({
            chapitre: d.chapitre, intitule_chapitre: d.intitule_chapitre,
            article: d.article, code_article: d.code_article, intitule_article: d.intitule_article,
            montant_apriori: 0, montant_aposteriori: d.montant_aposteriori, date: d.date
        });
    });

    donnees.sort(function(a, b) { return new Date(b.date) - new Date(a.date); });

    if (!donnees.length) { adAfficherVide(); return; }

    adDonnees = donnees;
    adChargerChartJS(function() {
        adMajStats(donnees);
        adMajTableau(donnees);
        if (chapVal) {
            let totalDepense = donnees.reduce(function(s, d) {
                return s + (d.montant_apriori || 0) + (d.montant_aposteriori || 0);
            }, 0);
            adChargerBudgetEtGraphique(chapVal, articleVal, totalDepense);
        }
    });
}

function adMajStats(donnees) {
    let totalApriori     = donnees.reduce(function(s, d) { return s + (d.montant_apriori     || 0); }, 0);
    let totalAposteriori = donnees.reduce(function(s, d) { return s + (d.montant_aposteriori || 0); }, 0);
    let total            = totalApriori + totalAposteriori;
    let nbArticles       = new Set(donnees.map(function(d) { return d.article; })).size;

    root_element.querySelector('#ad-total-depenses').textContent    = adFmt(total);
    root_element.querySelector('#ad-nb-articles').textContent       = nbArticles;
    root_element.querySelector('#ad-total-apriori').textContent     = adFmt(totalApriori);
    root_element.querySelector('#ad-total-aposteriori').textContent = adFmt(totalAposteriori);
}

function adMajTableau(donnees) {
    let tbody = root_element.querySelector('#ad-table-body');
    tbody.innerHTML = '';
    donnees.forEach(function(d) {
        let total = (d.montant_apriori || 0) + (d.montant_aposteriori || 0);
        let tr = document.createElement('tr');
        tr.innerHTML =
            '<td><strong>' + (d.chapitre || '—') + '</strong></td>' +
            '<td><strong>' + (d.code_article || d.article || '—') + '</strong></td>' +
            '<td>' + (d.intitule_article || '—') + '</td>' +
            '<td>' + (d.montant_apriori > 0 ? '<span class="badge-apriori">' + adFmt(d.montant_apriori) + '</span>' : '<span style="color:#ccc">—</span>') + '</td>' +
            '<td>' + (d.montant_aposteriori > 0 ? '<span class="badge-aposteriori">' + adFmt(d.montant_aposteriori) + '</span>' : '<span style="color:#ccc">—</span>') + '</td>' +
            '<td><strong>' + adFmt(total) + '</strong></td>' +
            '<td>' + adFmtDate(d.date) + '</td>';
        tbody.appendChild(tr);
    });
}

function adChargerBudgetEtGraphique(chapVal, articleVal, totalDepense) {
    var filters = articleVal
        ? [['article', '=', articleVal]]
        : [['article', 'in', adArticlesDeLaFaculte.length ? adArticlesDeLaFaculte : []]];

    if (chapVal && !articleVal) {
        filters = [['article', 'in', adArticlesDeLaFaculte]];
    }

    frappe.call({
        method: 'frappe.client.get_list',
        args: { doctype: 'Budget Article', filters: filters, fields: ['montant'], limit_page_length: 0 },
        callback: function(rB) {
            let budget  = (rB.message || []).reduce(function(s, b) { return s + (b.montant || 0); }, 0);
            let restant = Math.max(budget - totalDepense, 0);
            adAfficherGraphique(totalDepense, restant, budget);
        }
    });
}

function adAfficherGraphique(depense, restant, budget) {
    let section = root_element.querySelector('#ad-chart-section');
    let ctx     = root_element.querySelector('#ad-depensesChart');
    if (!ctx) return;

    section.style.display = 'block';
    let pct = budget > 0 ? Math.round(depense / budget * 100) : 0;

    root_element.querySelector('#ad-chart-title').textContent =
        'Budget : ' + adFmt(budget) + '   |   Dépensé : ' + adFmt(depense) + '   |   ' + pct + '% consommé';

    if (adChart) { try { adChart.destroy(); } catch(e) {} adChart = null; }

    ctx.parentElement.style.position = 'relative';
    ctx.parentElement.style.height   = '320px';

    adChart = new Chart(ctx.getContext('2d'), {
        type: 'pie',
        data: {
            labels: ['Dépensé', 'Restant'],
            datasets: [{
                data: [depense, restant],
                backgroundColor: ['#131246', '#1c3b22'],
                hoverBackgroundColor: ['#1b1a6e', '#295733'],
                borderWidth: 2,
                borderColor: '#ffffff'
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: { position: 'bottom', labels: { padding: 20, font: { size: 13 }, usePointStyle: true } },
                tooltip: {
                    callbacks: {
                        label: function(context) {
                            let p = budget > 0 ? ((context.parsed / budget) * 100).toFixed(1) : 0;
                            return ' ' + adFmt(context.parsed) + ' (' + p + '%)';
                        }
                    }
                }
            }
        }
    });
}

function adAfficherVide() {
    root_element.querySelector('#ad-table-body').innerHTML =
        '<tr><td colspan="7" class="no-data"><div class="no-data-icon">📭</div><div>Aucune dépense ne correspond à vos critères</div></td></tr>';
    root_element.querySelector('#ad-total-depenses').textContent    = '0 DA';
    root_element.querySelector('#ad-nb-articles').textContent       = '0';
    root_element.querySelector('#ad-total-apriori').textContent     = '0 DA';
    root_element.querySelector('#ad-total-aposteriori').textContent = '0 DA';
    root_element.querySelector('#ad-chart-section').style.display   = 'none';
    if (adChart) { adChart.destroy(); adChart = null; }
}

adBtnReset.addEventListener('click', function() {
    adSelectChapitre.value    = '';
    adSelectArticle.innerHTML = '<option value="">Tous les articles</option>';
    root_element.querySelector('#ad-date-debut').value              = '';
    root_element.querySelector('#ad-date-fin').value                = '';
    root_element.querySelector('#ad-total-depenses').textContent    = '0 DA';
    root_element.querySelector('#ad-nb-articles').textContent       = '0';
    root_element.querySelector('#ad-total-apriori').textContent     = '0 DA';
    root_element.querySelector('#ad-total-aposteriori').textContent = '0 DA';
    root_element.querySelector('#ad-chart-section').style.display   = 'none';
    root_element.querySelector('#ad-table-body').innerHTML          =
        '<tr><td colspan="7" class="loading">Sélectionnez des filtres et cliquez sur Appliquer</td></tr>';
    if (adChart) { adChart.destroy(); adChart = null; }
});

function adFmt(n) {
    return new Intl.NumberFormat('fr-DZ', { style: 'currency', currency: 'DZD', minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(n || 0);
}
function adFmtDate(s) {
    if (!s) return '—';
    return new Intl.DateTimeFormat('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(s));
}

