script:
// here root_element is provided by default

if (!window.Chart) {
    var scriptChart = document.createElement('script');
    scriptChart.src = 'https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.0/chart.umd.min.js';
    scriptChart.onload = function() { evoCharger(); };
    document.head.appendChild(scriptChart);
} else {
    evoCharger();
}

var MOIS = ['Jan','Fév','Mar','Avr','Mai','Jun','Jul','Aoû','Sep','Oct','Nov','Déc'];

function evoFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function evoCharger() {
    var annee = new Date().getFullYear();

    // ── Étape 0 : Faculté de l'utilisateur connecté ──
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'User',
            filters: { name: frappe.session.user },
            fieldname: 'faculte'
        },
        callback: function(r0) {
            var faculte = r0.message ? r0.message.faculte : null;

            // ── Étape 1 : Années budgétaires ──
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Annee Budgetaire',
                    fields: ['name'],
                    filters: faculte ? [['faculte', '=', faculte]] : [],
                    limit_page_length: 0
                },
                callback: function(rAn) {
                    var annees = (rAn.message || []).map(function(a) { return a.name; });

                    // ── Étape 2 : Articles ──
                    frappe.call({
                        method: 'frappe.client.get_list',
                        args: {
                            doctype: 'Article',
                            fields: ['name'],
                            filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                            limit_page_length: 0
                        },
                        callback: function(rArt) {
                            var articles = (rArt.message || []).map(function(a) { return a.name; });

                            var dataAP = new Array(12).fill(0);
                            var dataPR = new Array(12).fill(0);

                            // ── Étape 3 : Depense Interne Régularisé ──
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Depense Interne',
                                    fields: ['date_depense', 'montant_total'],
                                    filters: articles.length
                                        ? [['status', '=', 'Régularisé'], ['article', 'in', articles]]
                                        : [['status', '=', 'Régularisé']],
                                    limit_page_length: 0
                                },
                                callback: function(rD) {
                                    (rD.message || []).forEach(function(d) {
                                        if (d.date_depense) {
                                            var date = new Date(d.date_depense);
                                            if (date.getFullYear() === annee)
                                                dataAP[date.getMonth()] += (d.montant_total || 0);
                                        }
                                    });

                                    // ── Étape 4 : Fiche Budgetaire Dépense Visé CF ──
                                    frappe.call({
                                        method: 'frappe.client.get_list',
                                        args: {
                                            doctype: 'Fiche Budgetaire',
                                            fields: ['date_signature_doyen', 'montant_operation'],
                                            filters: articles.length
                                                ? [['type_article', '=', 'A priori'], ['type_fiche', '=', 'Dépense'], ['status', '=', 'Visé CF'], ['article', 'in', articles]]
                                                : [['type_article', '=', 'A priori'], ['type_fiche', '=', 'Dépense'], ['status', '=', 'Visé CF']],
                                            limit_page_length: 0
                                        },
                                        callback: function(rF) {
                                            (rF.message || []).forEach(function(f) {
                                                if (f.date_signature_doyen) {
                                                    var date = new Date(f.date_signature_doyen);
                                                    if (date.getFullYear() === annee)
                                                        dataPR[date.getMonth()] += (f.montant_operation || 0);
                                                }
                                            });

                                            evoAfficher(dataAP, dataPR, annee);
                                        }
                                    });
                                }
                            });
                        }
                    });
                }
            });
        }
    });
}

function evoAfficher(dataAP, dataPR, annee) {
    root_element.querySelector('#evo-loading').style.display    = 'none';
    root_element.querySelector('#evo-chart-wrap').style.display = 'block';

    var totalAP = dataAP.reduce(function(s, v) { return s + v; }, 0);
    var totalPR = dataPR.reduce(function(s, v) { return s + v; }, 0);
    root_element.querySelector('#evo-total-val').textContent = evoFmt(totalAP + totalPR);
    root_element.querySelector('#evo-ap-val').textContent    = evoFmt(totalAP);
    root_element.querySelector('#evo-pr-val').textContent    = evoFmt(totalPR);
    root_element.querySelector('#evo-sub').textContent       = 'Année ' + annee + ' — cumul mensuel';

    var ctx = root_element.querySelector('#evo-chart').getContext('2d');
    new Chart(ctx, {
        type: 'line',
        data: {
            labels: MOIS,
            datasets: [
                {
                    label: 'A posteriori (Dépense Interne)',
                    data: dataAP,
                    borderColor: '#3b82f6',
                    backgroundColor: 'rgba(59,130,246,0.1)',
                    borderWidth: 2,
                    pointBackgroundColor: '#3b82f6',
                    pointRadius: 5,
                    tension: 0.4,
                    fill: true
                },
                {
                    label: 'A priori (Fiche Budgétaire)',
                    data: dataPR,
                    borderColor: '#10b981',
                    backgroundColor: 'rgba(16,185,129,0.1)',
                    borderWidth: 2,
                    pointBackgroundColor: '#10b981',
                    pointRadius: 5,
                    tension: 0.4,
                    fill: true
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: {
                legend: { position: 'top', labels: { font: { size: 12 }, usePointStyle: true } },
                tooltip: {
                    callbacks: {
                        label: function(ctx) {
                            return ctx.dataset.label + ' : ' +
                                new Intl.NumberFormat('fr-DZ').format(Math.round(ctx.raw)) + ' DA';
                        }
                    }
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: {
                        callback: function(v) {
                            if (v >= 1000000) return (v/1000000).toFixed(1) + 'M';
                            if (v >= 1000)    return (v/1000).toFixed(0) + 'K';
                            return v;
                        }
                    },
                    grid: { color: '#f1f5f9' }
                },
                x: { grid: { display: false } }
            }
        }
    });
}

