script:
// here root_element is provided by default

var sbSeuil = 60;

// ── SEUIL DYNAMIQUE ───────────────────────────────
root_element.querySelector('#seuil-range').addEventListener('input', function() {
    sbSeuil = parseInt(this.value);
    root_element.querySelector('#seuil-display').textContent = sbSeuil + '%';
});

// ── BOUTON ACTUALISER ─────────────────────────────
root_element.querySelector('#btn-refresh').addEventListener('click', function() {
    sbCharger();
});

// ── CHARGEMENT AU DÉMARRAGE ───────────────────────
sbCharger();

function sbCharger() {
    root_element.querySelector('#table-body').innerHTML =
        '<tr><td colspan="6" class="loading">⏳ Chargement...</td></tr>';
    root_element.querySelector('#alertes-container').innerHTML = '';

    // ── Étape 0 : Faculté de l'utilisateur connecté ──
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'User',
            filters: { name: frappe.session.user },
            fieldname: 'faculte'
        },
        callback: function(r0) {
            var faculte = r0.message ? r0.message.faculte : null;

            // ── Étape 1 : Années budgétaires ──
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Annee Budgetaire',
                    fields: ['name'],
                    filters: faculte ? [['faculte', '=', faculte]] : [],
                    limit_page_length: 0
                },
                callback: function(rAn) {
                    var annees = (rAn.message || []).map(function(a) { return a.name; });

                    // ── Étape 2 : Articles ──
                    frappe.call({
                        method: 'frappe.client.get_list',
                        args: {
                            doctype: 'Article',
                            fields: ['name'],
                            filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                            limit_page_length: 0
                        },
                        callback: function(rArt) {
                            var articles = (rArt.message || []).map(function(a) { return a.name; });

                            if (!articles.length) {
                                root_element.querySelector('#table-body').innerHTML =
                                    '<tr><td colspan="6" class="no-data">Aucun article trouvé pour cette faculté</td></tr>';
                                return;
                            }

                            // ── Étape 3 : Budget Article ──
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Budget Article',
                                    fields: ['article', 'montant'],
                                    filters: [['article', 'in', articles]],
                                    limit_page_length: 0
                                },
                                callback: function(rB) {
                                    var budgets = rB.message || [];
                                    if (!budgets.length) {
                                        root_element.querySelector('#table-body').innerHTML =
                                            '<tr><td colspan="6" class="no-data">Aucun Budget Article trouvé</td></tr>';
                                        return;
                                    }

                                    // ── Étape 4 : Depense Interne Régularisé ──
                                    frappe.call({
                                        method: 'frappe.client.get_list',
                                        args: {
                                            doctype: 'Depense Interne',
                                            fields: ['article', 'montant_total'],
                                            filters: [['status', '=', 'Régularisé'], ['article', 'in', articles]],
                                            limit_page_length: 0
                                        },
                                        callback: function(rD) {
                                            var depMap = {};
                                            (rD.message || []).forEach(function(d) {
                                                if (!depMap[d.article]) depMap[d.article] = 0;
                                                depMap[d.article] += (d.montant_total || 0);
                                            });

                                            // ── Étape 5 : Fiche Budgetaire Dépense Visé CF ──
                                            frappe.call({
                                                method: 'frappe.client.get_list',
                                                args: {
                                                    doctype: 'Fiche Budgetaire',
                                                    fields: ['article', 'montant_operation'],
                                                    filters: [
                                                        ['type_fiche', '=', 'Dépense'],
                                                        ['status',     '=', 'Visé CF'],
                                                        ['article',    'in', articles]
                                                    ],
                                                    limit_page_length: 0
                                                },
                                                callback: function(rF) {
                                                    var fbMap = {};
                                                    (rF.message || []).forEach(function(f) {
                                                        if (!fbMap[f.article]) fbMap[f.article] = 0;
                                                        fbMap[f.article] += (f.montant_operation || 0);
                                                    });

                                                    // Construire les résultats
                                                    var resultats = [];
                                                    budgets.forEach(function(b) {
                                                        var depense = (depMap[b.article] || 0) + (fbMap[b.article] || 0);
                                                        var budget  = b.montant || 0;
                                                        var pct     = budget > 0 ? (depense / budget) * 100 : 0;
                                                        resultats.push({
                                                            article: b.article,
                                                            budget:  budget,
                                                            depense: depense,
                                                            reste:   budget - depense,
                                                            pct:     pct
                                                        });
                                                    });

                                                    sbAfficher(resultats);
                                                }
                                            });
                                        }
                                    });
                                }
                            });
                        }
                    });
                }
            });
        }
    });
}

// ── AFFICHAGE ─────────────────────────────────────
function sbAfficher(donnees) {
    donnees.sort(function(a, b) { return b.pct - a.pct; });
    sbAfficherAlertes(donnees);
    sbAfficherTableau(donnees);
}

function sbAfficherAlertes(donnees) {
    var container = root_element.querySelector('#alertes-container');
    container.innerHTML = '';
    var enAlerte = donnees.filter(function(d) { return d.pct >= sbSeuil; });

    if (!enAlerte.length) {
        container.innerHTML =
            '<div class="alerte-banniere ok">' +
            '<span class="alerte-icon">✅</span>' +
            '<span class="alerte-text">Tous les articles sont en dessous du seuil de ' + sbSeuil + '%</span>' +
            '</div>';
        return;
    }

    enAlerte.forEach(function(d) {
        var classe, icon, texte;
        if (d.pct >= 100)      { classe = 'critique'; icon = '🚨'; texte = 'Budget DÉPASSÉ'; }
        else if (d.pct >= 90)  { classe = 'danger';   icon = '🔴'; texte = 'Budget critique (≥ 90%)'; }
        else                   { classe = 'warning';  icon = '⚠️'; texte = 'Budget en alerte (≥ ' + sbSeuil + '%)'; }

        var div = document.createElement('div');
        div.className = 'alerte-banniere ' + classe;
        div.innerHTML =
            '<span class="alerte-icon">' + icon + '</span>' +
            '<div class="alerte-text">' +
                '<strong>' + d.article + '</strong> — ' + texte +
                ' — Dépensé : ' + sbFmt(d.depense) + ' / ' + sbFmt(d.budget) +
                ' — Reste : ' + sbFmt(d.reste) +
            '</div>' +
            '<span class="alerte-pct">' + d.pct.toFixed(1) + '%</span>';
        container.appendChild(div);
    });
}

function sbAfficherTableau(donnees) {
    var tbody = root_element.querySelector('#table-body');
    tbody.innerHTML = '';

    donnees.forEach(function(d) {
        var pctArrondi = Math.min(d.pct, 100).toFixed(1);
        var classe     = sbGetClasse(d.pct);
        var largeur    = Math.min(d.pct, 100).toFixed(1);

        var tr = document.createElement('tr');
        tr.innerHTML =
            '<td><strong>' + d.article + '</strong></td>' +
            '<td>' + sbFmt(d.budget)  + '</td>' +
            '<td>' + sbFmt(d.depense) + '</td>' +
            '<td style="color:' + (d.reste < 0 ? '#ef4444' : '#059669') + '"><strong>' + sbFmt(d.reste) + '</strong></td>' +
            '<td>' +
                '<div class="progress-wrap">' +
                    '<div class="progress-track">' +
                        '<div class="progress-fill ' + classe + '" style="width:' + largeur + '%"></div>' +
                    '</div>' +
                    '<span class="progress-pct ' + classe + '">' + pctArrondi + '%</span>' +
                '</div>' +
            '</td>' +
            '<td>' + sbBadge(d.pct) + '</td>';
        tbody.appendChild(tr);
    });
}

function sbGetClasse(pct) {
    if (pct >= 100)     return 'critique';
    if (pct >= 90)      return 'danger';
    if (pct >= sbSeuil) return 'warning';
    return 'ok';
}

function sbBadge(pct) {
    if (pct >= 100)     return '<span class="badge badge-depasse">Dépassé</span>';
    if (pct >= 90)      return '<span class="badge badge-danger">Critique</span>';
    if (pct >= sbSeuil) return '<span class="badge badge-warning">Alerte</span>';
    return '<span class="badge badge-ok">Normal</span>';
}

function sbFmt(n) {
    return new Intl.NumberFormat('fr-DZ', {
        style: 'currency', currency: 'DZD',
        minimumFractionDigits: 0, maximumFractionDigits: 0
    }).format(n || 0);
}

