script:
// here root_element is provided by default

function alrtFmt(n) {
    if (!n && n !== 0) return '—';
    return new Intl.NumberFormat('fr-DZ').format(Math.round(n)) + ' DA';
}

function alrtNiveau(pct) {
    if (pct >= 80) return 'danger';
    if (pct >= 60) return 'orange';
    if (pct >= 40) return 'warn';
    return null;
}

function alrtIcone(niveau) {
    if (niveau === 'danger') return '🚨';
    if (niveau === 'orange') return '🔶';
    return '⚠️';
}

function alrtLabel(niveau) {
    if (niveau === 'danger') return 'URGENT — Dépassement imminent';
    if (niveau === 'orange') return 'CRITIQUE — Budget très entamé';
    return 'ATTENTION — Seuil atteint';
}

var alrtMap = {};

// ── Étape 0 : Faculté de l'utilisateur connecté ──
frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r0) {
        var faculte = r0.message ? r0.message.faculte : null;

        // ── Étape 1 : Années budgétaires de la faculté ──
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Annee Budgetaire',
                fields: ['name'],
                filters: faculte ? [['faculte', '=', faculte]] : [],
                limit_page_length: 0
            },
            callback: function(rAn) {
                var annees = (rAn.message || []).map(function(a) { return a.name; });

                // ── Étape 2 : Articles de ces années ──
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Article',
                        fields: ['name'],
                        filters: annees.length ? [['annee_budgetaire', 'in', annees]] : [],
                        limit_page_length: 0
                    },
                    callback: function(rArt) {
                        var articles = (rArt.message || []).map(function(a) { return a.name; });

                        if (!articles.length) {
                            root_element.querySelector('#alrt-liste').innerHTML =
                                '<div class="alrt-ok"><div class="alrt-ok-icon">📭</div><div>Aucun article trouvé pour cette faculté</div></div>';
                            root_element.querySelector('#alrt-sub').textContent = 'Aucune donnée';
                            return;
                        }

                        // ── Étape 3 : Budget Article ──
                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'Budget Article',
                                fields: ['article', 'montant'],
                                filters: [['article', 'in', articles]],
                                limit_page_length: 0
                            },
                            callback: function(r1) {
                                (r1.message || []).forEach(function(b) {
                                    if (!alrtMap[b.article]) alrtMap[b.article] = { budget: 0, depense: 0, code: b.article, intitule: '—', chapitre: '—' };
                                    alrtMap[b.article].budget += (b.montant || 0);
                                });

                                if (!Object.keys(alrtMap).length) {
                                    root_element.querySelector('#alrt-liste').innerHTML =
                                        '<div class="alrt-ok"><div class="alrt-ok-icon">📭</div><div>Aucun budget article trouvé</div></div>';
                                    root_element.querySelector('#alrt-sub').textContent = 'Aucune donnée';
                                    return;
                                }

                                // ── Étape 4 : Depense Interne Régularisé ──
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Depense Interne',
                                        fields: ['article', 'montant_total'],
                                        filters: [['status', '=', 'Régularisé'], ['article', 'in', articles]],
                                        limit_page_length: 0
                                    },
                                    callback: function(r2) {
                                        (r2.message || []).forEach(function(d) {
                                            if (!d.article) return;
                                            if (!alrtMap[d.article]) alrtMap[d.article] = { budget: 0, depense: 0, code: d.article, intitule: '—', chapitre: '—' };
                                            alrtMap[d.article].depense += (d.montant_total || 0);
                                        });

                                        // ── Étape 5 : Fiche Budgetaire Dépense Visé CF ──
                                        frappe.call({
                                            method: 'frappe.client.get_list',
                                            args: {
                                                doctype: 'Fiche Budgetaire',
                                                fields: ['article', 'montant_operation'],
                                                filters: [
                                                    ['type_fiche', '=', 'Dépense'],
                                                    ['status',     '=', 'Visé CF'],
                                                    ['article',    'in', articles]
                                                ],
                                                limit_page_length: 0
                                            },
                                            callback: function(r3) {
                                                (r3.message || []).forEach(function(f) {
                                                    if (!f.article) return;
                                                    if (!alrtMap[f.article]) alrtMap[f.article] = { budget: 0, depense: 0, code: f.article, intitule: '—', chapitre: '—' };
                                                    alrtMap[f.article].depense += (f.montant_operation || 0);
                                                });

                                                // ── Étape 6 : Enrichir code/intitule/chapitre ──
                                                var articleKeys = Object.keys(alrtMap);
                                                var pending = articleKeys.length;

                                                articleKeys.forEach(function(articleName) {
                                                    frappe.call({
                                                        method: 'frappe.client.get_value',
                                                        args: { doctype: 'Article', filters: { name: articleName }, fieldname: ['code_article', 'intitule_article', 'chapitre'] },
                                                        callback: function(rA) {
                                                            if (rA.message) {
                                                                alrtMap[articleName].code     = rA.message.code_article     || articleName;
                                                                alrtMap[articleName].intitule = rA.message.intitule_article || '—';
                                                                alrtMap[articleName].chapitre = rA.message.chapitre         || '—';
                                                            }
                                                            pending--;
                                                            if (pending === 0) alrtAfficher();
                                                        }
                                                    });
                                                });
                                            }
                                        });
                                    }
                                });
                            }
                        });
                    }
                });
            }
        });
    }
});

// ── AFFICHAGE ─────────────────────────────────────
function alrtAfficher() {
    var donnees = Object.keys(alrtMap).map(function(k) {
        var d = alrtMap[k];
        var pct = d.budget > 0 ? (d.depense / d.budget) * 100 : 0;
        return { code: d.code, intitule: d.intitule, chapitre: d.chapitre, budget: d.budget, depense: d.depense, reste: d.budget - d.depense, pct: pct };
    });

    donnees.sort(function(a, b) { return b.pct - a.pct; });

    var nbWarn = 0, nbOrange = 0, nbDanger = 0;
    var alertes = [];

    donnees.forEach(function(d) {
        var niveau = alrtNiveau(Math.round(d.pct));
        if (!niveau) return;
        if (niveau === 'danger')      nbDanger++;
        else if (niveau === 'orange') nbOrange++;
        else                          nbWarn++;
        alertes.push(Object.assign({}, d, { niveau: niveau }));
    });

    root_element.querySelector('#kpi-warn-val').textContent   = nbWarn;
    root_element.querySelector('#kpi-orange-val').textContent = nbOrange;
    root_element.querySelector('#kpi-danger-val').textContent = nbDanger;

    var totalAlertes = nbWarn + nbOrange + nbDanger;
    root_element.querySelector('#alrt-sub').textContent =
        totalAlertes > 0
            ? totalAlertes + ' article(s) nécessitent votre attention'
            : 'Tous les budgets sont sous contrôle ✓';

    var liste = root_element.querySelector('#alrt-liste');

    if (!alertes.length) {
        liste.innerHTML =
            '<div class="alrt-ok">' +
            '<div class="alrt-ok-icon">✅</div>' +
            '<div>Tous les articles sont sous le seuil de 40%</div>' +
            '<div style="font-size:12px;font-weight:400;margin-top:4px;color:#166534">Aucune alerte budgétaire pour le moment</div>' +
            '</div>';
        return;
    }

    liste.innerHTML = alertes.map(function(a) {
        var n   = a.niveau;
        var pct = Math.round(a.pct);
        return '<div class="alrt-card alrt-card-' + n + '">' +
            '<div class="alrt-card-icon">' + alrtIcone(n) + '</div>' +
            '<div class="alrt-card-body">' +
                '<div class="alrt-card-title">' + a.code + ' — ' + a.intitule + '</div>' +
                '<div class="alrt-card-detail">' +
                    '<span style="color:#94a3b8">Chapitre : ' + a.chapitre + '</span><br>' +
                    'Budget : <span class="alrt-montant">' + alrtFmt(a.budget) + '</span> &nbsp;|&nbsp; ' +
                    'Dépensé : <span class="alrt-montant">' + alrtFmt(a.depense) + '</span> &nbsp;|&nbsp; ' +
                    'Restant : <span class="alrt-montant" style="color:' + (a.reste < 0 ? '#ef4444' : '#059669') + '">' + alrtFmt(a.reste) + '</span>' +
                '</div>' +
                '<div class="alrt-bar-wrap"><div class="alrt-bar-fill alrt-bar-' + n + '" style="width:' + Math.min(pct, 100) + '%"></div></div>' +
                '<span class="alrt-badge alrt-badge-' + n + '">' + alrtLabel(n) + '</span>' +
            '</div>' +
            '<div class="alrt-card-right">' +
                '<div class="alrt-pct alrt-pct-' + n + '">' + pct + '%</div>' +
                '<div style="font-size:10px;color:#94a3b8;margin-top:2px">consommé</div>' +
            '</div>' +
        '</div>';
    }).join('');
}

