script:
// Navigation entre les pages
let nav_buttons = root_element.querySelectorAll('.nav-btn');
let page_contents = root_element.querySelectorAll('.page-content');

nav_buttons.forEach(btn => {
    btn.addEventListener('click', function() {
        const pageId = this.getAttribute('data-page');
        
        // Enlever active de tous les boutons
        nav_buttons.forEach(b => b.classList.remove('active'));
        
        // Enlever active de toutes les pages
        page_contents.forEach(p => p.classList.remove('active'));
        
        // Ajouter active au bouton cliqué
        this.classList.add('active');
        
        // Ajouter active à la page correspondante
        let target_page = root_element.querySelector('#' + pageId);
        if (target_page) {
            target_page.classList.add('active');
        }
    });
});

// Navigation vers les pages ERPNext au clic sur les cartes
let cards = root_element.querySelectorAll('.card');
cards.forEach(card => {
    card.addEventListener('click', function() {
        const route = this.getAttribute('data-route');
        if (route) {
            // Découper la route en parties
            const parts = route.split('/');
            
            if (parts[0] === 'Form') {
                // Navigation vers un formulaire
                frappe.set_route('Form', parts[1], parts[2] || 'new');
            } else if (parts[0] === 'List') {
                // Navigation vers une liste
                frappe.set_route('List', parts[1]);
            } else if (parts[0] === 'query-report') {
                // Navigation vers un rapport
                frappe.set_route('query-report', parts[1]);
            }
        }
    });
});
// Accordéons pour Opérations
let accordions = root_element.querySelectorAll('.accordion-btn');
accordions.forEach(btn => {
    btn.addEventListener('click', () => {
        let content = btn.nextElementSibling;
        content.style.display = (content.style.display === 'block') ? 'none' : 'block';
    });
});

style:
.simple-finance-nav {
    padding: 20px;
}

/* Boutons de navigation */
.nav-buttons {
    display: flex;
    gap: 10px;
    margin-bottom: 30px;
    background: #f5f5f5;
    padding: 10px;
    border-radius: 8px;
}
.nav-btn {
    flex: 1;
    padding: 15px 20px;
    background: white;
    border: 2px solid #ddd;
    border-radius: 6px;
    cursor: pointer;
    font-size: 16px;
    font-weight: 600;
    transition: all 0.3s;
}
.nav-btn:hover {
    background: #e8edf2;
    border-color: #1a2332;
}
.nav-btn.active {
    background: #1a2332;
    color: white;
    border-color: #1a2332;
}

/* Pages */
.pages-container { min-height: 300px; }
.page-content { display: none; }
.page-content.active {
    display: block;
    animation: fadeIn 0.3s ease-in;
}
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(10px); }
    to   { opacity: 1; transform: translateY(0); }
}
.page-content h2 {
    color: #1a2332;
    margin-bottom: 20px;
    font-size: 24px;
    border-left: 4px solid #1a2332;
    padding-left: 15px;
}

/* Accordéon */
.accordion-content {
    display: none;
    margin-bottom: 30px;
    padding-left: 10px;
}
.accordion-btn {
    width: 100%;
    text-align: left;
    padding: 15px 20px;
    font-size: 16px;
    font-weight: 600;
    background: #f5f5f5;
    border: 1px solid #ddd;
    border-radius: 8px;
    cursor: pointer;
    margin-bottom: 10px;
    transition: all 0.3s;
}
.accordion-btn:hover {
    background: #e8edf2;
    border-color: #1a2332;
}

/* Cartes */
.cards {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 20px;
}
.card {
    background: white;
    padding: 25px;
    border-radius: 10px;
    box-shadow: 0 3px 10px rgba(0,0,0,0.1);
    cursor: pointer;
    transition: all 0.3s;
    border: 1px solid #e9ecef;
}
.card:hover {
    transform: translateY(-3px);
    box-shadow: 0 6px 15px rgba(26,35,50,0.2);
    border-color: #1a2332;
}
.card h3 {
    margin: 0 0 12px 0;
    color: #1a2332;
    font-size: 18px;
}
.card p {
    margin: 0;
    color: #6c757d;
    font-size: 14px;
}

/* Responsive */
@media (max-width: 768px) {
    .nav-buttons { flex-direction: column; }
    .cards { grid-template-columns: 1fr; gap: 15px; }
}

script:
// here root_element is provided by default

frappe.call({
    method: 'frappe.client.get_value',
    args: {
        doctype: 'User',
        filters: { name: frappe.session.user },
        fieldname: 'faculte'
    },
    callback: function(r) {
        var faculte = r.message ? r.message.faculte : null;
        if (!faculte) {
            root_element.querySelector('#ws-faculte-nom').textContent = 'Centre Financier';
            return;
        }

        frappe.call({
            method: 'frappe.client.get_value',
            args: {
                doctype: 'Faculte',
                filters: { name: faculte },
                fieldname: 'intitule_faculte'
            },
            callback: function(rF) {
                var nom = rF.message ? (rF.message.intitule_faculte || faculte) : faculte;
                root_element.querySelector('#ws-faculte-nom').textContent = nom;
            }
        });
    }
});

style:
.custom-workspace {
    background-color: #1a2332 !important;
    padding: 20px;
    border-radius: 10px;
    font-family: "Arial", sans-serif;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
    text-align: center;
}
.workspace-header {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 20px;
    flex-wrap: wrap;
}
.workspace-logo {
    width: 60px;
    height: auto;
    filter: none;
}
.workspace-title {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
}
.workspace-title h2 {
    margin: 0 0 20px 0;
    color: #ffffff !important;
}
.workspace-title h3 {
    margin: 0;
    color: rgba(255,255,255,0.8) !important;
}
.workspace-buttons {
    margin-top: 20px;
    display: flex;
    justify-content: center;
    flex-wrap: wrap;
    gap: 15px;
}
.workspace-btn {
    padding: 10px 20px;
    background-color: #2d3f55;
    color: white;
    text-decoration: none;
    border-radius: 5px;
    transition: background-color 0.3s;
}
.workspace-btn:hover {
    background-color: #0d1829;
}
.workspace-note {
    margin-top: 20px;
    color: rgba(255,255,255,0.7) !important;
    font-size: 16px;
    text-align: center;
}
